INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What is the first stage of the Design Thinking process?', '[{"id":"a","text":"Prototype","is_correct":false},{"id":"b","text":"Empathize","is_correct":true},{"id":"c","text":"Define","is_correct":false},{"id":"d","text":"Test","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Design Thinking is best described as:', '[{"id":"a","text":"A software development methodology","is_correct":false},{"id":"b","text":"A human-centered approach to innovation and problem solving","is_correct":true},{"id":"c","text":"A project management framework","is_correct":false},{"id":"d","text":"A financial planning model","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What does an empathy map primarily capture?', '[{"id":"a","text":"Market sizing and revenue projections","is_correct":false},{"id":"b","text":"What users say, think, feel, and do","is_correct":true},{"id":"c","text":"Technical architecture requirements","is_correct":false},{"id":"d","text":"Brand identity guidelines","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Which stage of Design Thinking involves reframing the problem as an actionable statement?', '[{"id":"a","text":"Empathize","is_correct":false},{"id":"b","text":"Prototype","is_correct":false},{"id":"c","text":"Define","is_correct":true},{"id":"d","text":"Ideate","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'The "How Might We" (HMW) question is used in which stage?', '[{"id":"a","text":"Test","is_correct":false},{"id":"b","text":"Prototype","is_correct":false},{"id":"c","text":"Empathize","is_correct":false},{"id":"d","text":"Define","is_correct":true}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What is the purpose of rapid prototyping in Design Thinking?', '[{"id":"a","text":"To create the final product","is_correct":false},{"id":"b","text":"To quickly test ideas and gather feedback before investing heavily","is_correct":true},{"id":"c","text":"To document technical specifications","is_correct":false},{"id":"d","text":"To finalize the business model","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'A persona is best defined as:', '[{"id":"a","text":"A real user who participates in testing","is_correct":false},{"id":"b","text":"A fictional character representing a user segment based on research","is_correct":true},{"id":"c","text":"A list of product features","is_correct":false},{"id":"d","text":"A marketing campaign avatar","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Which organization is most associated with popularizing Design Thinking?', '[{"id":"a","text":"McKinsey","is_correct":false},{"id":"b","text":"IDEO","is_correct":true},{"id":"c","text":"Google","is_correct":false},{"id":"d","text":"Apple","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What does "divergent thinking" mean in the Ideate stage?', '[{"id":"a","text":"Narrowing down to one best solution","is_correct":false},{"id":"b","text":"Generating as many ideas as possible without judgment","is_correct":true},{"id":"c","text":"Testing ideas with users","is_correct":false},{"id":"d","text":"Documenting design decisions","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Design Thinking is considered iterative because:', '[{"id":"a","text":"It follows a strict linear sequence","is_correct":false},{"id":"b","text":"Teams can move back and forth between stages based on learnings","is_correct":true},{"id":"c","text":"It requires repeating the same task three times","is_correct":false},{"id":"d","text":"It uses agile sprints exclusively","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What is the primary goal of the Empathize stage?', '[{"id":"a","text":"To build a working prototype","is_correct":false},{"id":"b","text":"To deeply understand users and their context through observation and interviews","is_correct":true},{"id":"c","text":"To define the project budget","is_correct":false},{"id":"d","text":"To select the technology stack","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'A Point of View (POV) statement in Design Thinking contains:', '[{"id":"a","text":"User + Need + Insight","is_correct":true},{"id":"b","text":"Problem + Budget + Timeline","is_correct":false},{"id":"c","text":"Feature + Technology + Market","is_correct":false},{"id":"d","text":"Goal + Risk + Assumption","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Which method is most effective for building empathy during user research?', '[{"id":"a","text":"Analyzing competitor websites","is_correct":false},{"id":"b","text":"Conducting contextual observation and in-depth interviews","is_correct":true},{"id":"c","text":"Reviewing sales reports","is_correct":false},{"id":"d","text":"Running online surveys with closed questions","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What is a common anti-pattern in Design Thinking?', '[{"id":"a","text":"Testing prototypes with real users","is_correct":false},{"id":"b","text":"Jumping to solutions before properly defining the problem","is_correct":true},{"id":"c","text":"Generating many ideas during ideation","is_correct":false},{"id":"d","text":"Iterating based on feedback","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'The Testing stage in Design Thinking is intended to:', '[{"id":"a","text":"Launch the product to market","is_correct":false},{"id":"b","text":"Generate new ideas","is_correct":false},{"id":"c","text":"Learn about users and refine solutions based on their feedback","is_correct":true},{"id":"d","text":"Present results to stakeholders","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Which of the following best describes convergent thinking?', '[{"id":"a","text":"Producing unlimited creative ideas","is_correct":false},{"id":"b","text":"Narrowing options to identify the most promising solution","is_correct":true},{"id":"c","text":"Asking open-ended questions","is_correct":false},{"id":"d","text":"Observing users in their environment","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What should a good problem statement focus on?', '[{"id":"a","text":"The solution the team wants to build","is_correct":false},{"id":"b","text":"The user need rather than a specific technology or feature","is_correct":true},{"id":"c","text":"The company revenue targets","is_correct":false},{"id":"d","text":"The competitor weaknesses","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Which prototype fidelity is most appropriate for early-stage Design Thinking?', '[{"id":"a","text":"High-fidelity pixel-perfect mockup","is_correct":false},{"id":"b","text":"Low-fidelity paper prototype or sketch","is_correct":true},{"id":"c","text":"Fully coded production build","is_correct":false},{"id":"d","text":"Video advertisement","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'Design Sprints, popularized by Google Ventures, compress the Design Thinking process into:', '[{"id":"a","text":"One year","is_correct":false},{"id":"b","text":"One month","is_correct":false},{"id":"c","text":"Five days","is_correct":true},{"id":"d","text":"Two weeks","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES101'), 'multiple_choice', 'What makes Design Thinking "human-centered"?', '[{"id":"a","text":"It prioritizes the needs, behaviors, and feelings of the end user throughout the process","is_correct":true},{"id":"b","text":"It is designed by humans rather than machines","is_correct":false},{"id":"c","text":"It focuses on the human resources department","is_correct":false},{"id":"d","text":"It uses human-readable documentation","is_correct":false}]', 1, true, true, 3);
