INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What is the term for the small decorative strokes at the ends of letterforms?', '[{"id":"a","text":"Serifs","is_correct":true},{"id":"b","text":"Ascenders","is_correct":false},{"id":"c","text":"Bowls","is_correct":false},{"id":"d","text":"Counters","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Which of these is a sans-serif typeface?', '[{"id":"a","text":"Times New Roman","is_correct":false},{"id":"b","text":"Georgia","is_correct":false},{"id":"c","text":"Helvetica","is_correct":true},{"id":"d","text":"Garamond","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What does "leading" refer to in typography?', '[{"id":"a","text":"The weight of a typeface","is_correct":false},{"id":"b","text":"The spacing between lines of text","is_correct":true},{"id":"c","text":"The width of letterforms","is_correct":false},{"id":"d","text":"The contrast between thick and thin strokes","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Kerning refers to:', '[{"id":"a","text":"The space between lines of text","is_correct":false},{"id":"b","text":"The overall spacing of all characters in a block of text","is_correct":false},{"id":"c","text":"The adjustment of space between specific pairs of characters","is_correct":true},{"id":"d","text":"The width of the type column","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What is an ascender in type anatomy?', '[{"id":"a","text":"The part of a lowercase letter that extends above the x-height","is_correct":true},{"id":"b","text":"The part of a letter that descends below the baseline","is_correct":false},{"id":"c","text":"The curved part of letters like O and C","is_correct":false},{"id":"d","text":"The diagonal stroke in letters like N and Z","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Which font pairing principle suggests combining a serif with a sans-serif?', '[{"id":"a","text":"Contrast pairing","is_correct":true},{"id":"b","text":"Similarity pairing","is_correct":false},{"id":"c","text":"Monospace pairing","is_correct":false},{"id":"d","text":"Slab pairing","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What does "tracking" (letter-spacing) primarily affect?', '[{"id":"a","text":"Individual character pairs","is_correct":false},{"id":"b","text":"The overall density and feel of a text block","is_correct":true},{"id":"c","text":"The vertical rhythm of text","is_correct":false},{"id":"d","text":"The cap height of uppercase letters","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'The x-height in typography refers to:', '[{"id":"a","text":"The height of uppercase letters","is_correct":false},{"id":"b","text":"The height of lowercase letters excluding ascenders and descenders","is_correct":true},{"id":"c","text":"The point size of the typeface","is_correct":false},{"id":"d","text":"The width of the letter X specifically","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Which classification includes typefaces like Courier and Lucida Console?', '[{"id":"a","text":"Script","is_correct":false},{"id":"b","text":"Slab Serif","is_correct":false},{"id":"c","text":"Monospace","is_correct":true},{"id":"d","text":"Blackletter","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'For body text readability on screens, the recommended line length is approximately:', '[{"id":"a","text":"20-30 characters","is_correct":false},{"id":"b","text":"45-75 characters","is_correct":true},{"id":"c","text":"100-120 characters","is_correct":false},{"id":"d","text":"10-15 words","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What is typographic hierarchy used to achieve?', '[{"id":"a","text":"To use as many fonts as possible in a design","is_correct":false},{"id":"b","text":"To guide the reader through content by establishing visual importance","is_correct":true},{"id":"c","text":"To ensure all text is the same size","is_correct":false},{"id":"d","text":"To maximize the number of words per page","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'A "display" typeface is best suited for:', '[{"id":"a","text":"Long paragraphs of body text","is_correct":false},{"id":"b","text":"Legal documents and contracts","is_correct":false},{"id":"c","text":"Headlines and short decorative text","is_correct":true},{"id":"d","text":"Captions and footnotes","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Which WCAG guideline relates directly to text contrast for accessibility?', '[{"id":"a","text":"WCAG 1.1 — Text Alternatives","is_correct":false},{"id":"b","text":"WCAG 1.4 — Distinguishable content including contrast ratios","is_correct":true},{"id":"c","text":"WCAG 2.1 — Keyboard accessible","is_correct":false},{"id":"d","text":"WCAG 3.1 — Readable","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What is a "widow" in typography?', '[{"id":"a","text":"A single short line at the end of a paragraph left at the top of a column","is_correct":true},{"id":"b","text":"A letter with an extremely long descender","is_correct":false},{"id":"c","text":"Unused white space in a layout","is_correct":false},{"id":"d","text":"A decorative drop cap at the start of a paragraph","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Variable fonts allow designers to:', '[{"id":"a","text":"Load multiple separate font files at once","is_correct":false},{"id":"b","text":"Adjust weight, width, and other axes continuously in a single font file","is_correct":true},{"id":"c","text":"Automatically convert raster fonts to vector","is_correct":false},{"id":"d","text":"Use fonts without licensing restrictions","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What is the baseline in typography?', '[{"id":"a","text":"The imaginary line on which most characters sit","is_correct":true},{"id":"b","text":"The minimum font size allowed","is_correct":false},{"id":"c","text":"The default line-height value","is_correct":false},{"id":"d","text":"The bottom margin of a text box","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Why should designers generally avoid using more than two or three typefaces in a single design?', '[{"id":"a","text":"Licensing costs increase with more fonts","is_correct":false},{"id":"b","text":"Too many typefaces creates visual chaos and undermines hierarchy","is_correct":true},{"id":"c","text":"Browsers cannot render more than three fonts","is_correct":false},{"id":"d","text":"Font file sizes become too large","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'Which of the following is a slab-serif typeface?', '[{"id":"a","text":"Futura","is_correct":false},{"id":"b","text":"Baskerville","is_correct":false},{"id":"c","text":"Rockwell","is_correct":true},{"id":"d","text":"Gill Sans","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES103'), 'multiple_choice', 'What does "optical sizing" refer to in type design?', '[{"id":"a","text":"Using different font weights for display vs. body text","is_correct":false},{"id":"b","text":"Designing typeface variants optimized for different size ranges for better legibility","is_correct":true},{"id":"c","text":"Resizing fonts proportionally with the viewport","is_correct":false},{"id":"d","text":"Adjusting tracking based on screen resolution","is_correct":false}]', 1, true, true, 3);
