INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'What does "saturation" refer to in color theory?', '[{"id":"a","text":"The brightness or darkness of a color","is_correct":false},{"id":"b","text":"The purity or intensity of a color","is_correct":true},{"id":"c","text":"The temperature of a color","is_correct":false},{"id":"d","text":"The hue position on the color wheel","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Which color harmony uses three colors equally spaced on the color wheel?', '[{"id":"a","text":"Analogous","is_correct":false},{"id":"b","text":"Complementary","is_correct":false},{"id":"c","text":"Triadic","is_correct":true},{"id":"d","text":"Split-complementary","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'The WCAG AA standard requires a minimum contrast ratio of what for normal text?', '[{"id":"a","text":"2:1","is_correct":false},{"id":"b","text":"3:1","is_correct":false},{"id":"c","text":"4.5:1","is_correct":true},{"id":"d","text":"7:1","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'What is a tint in color theory?', '[{"id":"a","text":"A color mixed with black","is_correct":false},{"id":"b","text":"A color mixed with gray","is_correct":false},{"id":"c","text":"A color mixed with white","is_correct":true},{"id":"d","text":"The shadow version of a color","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Analogous color schemes use colors that are:', '[{"id":"a","text":"Opposite on the color wheel","is_correct":false},{"id":"b","text":"Adjacent to each other on the color wheel","is_correct":true},{"id":"c","text":"Equally spaced in a triangle","is_correct":false},{"id":"d","text":"The same hue at different brightness levels","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Blue is frequently used by financial and technology brands because it conveys:', '[{"id":"a","text":"Excitement and energy","is_correct":false},{"id":"b","text":"Trust, stability, and reliability","is_correct":true},{"id":"c","text":"Warmth and friendliness","is_correct":false},{"id":"d","text":"Luxury and exclusivity","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'What is the 60-30-10 rule in color application?', '[{"id":"a","text":"A formula for mixing paint pigments","is_correct":false},{"id":"b","text":"A guideline for distributing dominant, secondary, and accent colors in a design","is_correct":true},{"id":"c","text":"A contrast ratio requirement for accessibility","is_correct":false},{"id":"d","text":"The percentage of warm colors recommended in a palette","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Why is color alone insufficient as a design indicator?', '[{"id":"a","text":"Colors look different on every screen","is_correct":false},{"id":"b","text":"Color-blind users may not perceive color differences, so additional visual cues are needed","is_correct":true},{"id":"c","text":"Color cannot be printed accurately","is_correct":false},{"id":"d","text":"Color choices are subjective and have no meaning","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'What is the primary difference between hue and value?', '[{"id":"a","text":"Hue is the name of the color; value is its lightness or darkness","is_correct":true},{"id":"b","text":"Hue is the brightness; value is the temperature","is_correct":false},{"id":"c","text":"Hue is only for print; value is for screens","is_correct":false},{"id":"d","text":"They are the same concept","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Split-complementary harmony uses:', '[{"id":"a","text":"A color and the two colors adjacent to its complement","is_correct":true},{"id":"b","text":"Two pairs of complementary colors","is_correct":false},{"id":"c","text":"Colors from opposite quadrants of the wheel","is_correct":false},{"id":"d","text":"Only warm or only cool colors","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Dark mode design requires careful attention to color because:', '[{"id":"a","text":"Bright saturated colors appear more vibrant and jarring on dark backgrounds","is_correct":true},{"id":"b","text":"Dark mode only works with grayscale palettes","is_correct":false},{"id":"c","text":"Color psychology reverses in dark mode","is_correct":false},{"id":"d","text":"WCAG does not apply to dark mode","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Which color type of blindness affects red-green perception and is most common?', '[{"id":"a","text":"Tritanopia","is_correct":false},{"id":"b","text":"Monochromacy","is_correct":false},{"id":"c","text":"Deuteranopia or Protanopia","is_correct":true},{"id":"d","text":"Achromatopsia","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'What does the HSL color model stand for?', '[{"id":"a","text":"High-Saturation-Luminance","is_correct":false},{"id":"b","text":"Hue-Saturation-Lightness","is_correct":true},{"id":"c","text":"Hue-Shade-Layer","is_correct":false},{"id":"d","text":"Hex-Spectrum-Lightness","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'In digital design, a token system for color helps teams by:', '[{"id":"a","text":"Allowing designers to avoid using color entirely","is_correct":false},{"id":"b","text":"Providing named, reusable color variables that ensure consistency across components","is_correct":true},{"id":"c","text":"Reducing the file size of images","is_correct":false},{"id":"d","text":"Automatically converting RGB to CMYK","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'Warm colors (reds, oranges, yellows) are typically perceived as:', '[{"id":"a","text":"Receding and calming","is_correct":false},{"id":"b","text":"Advancing and energetic","is_correct":true},{"id":"c","text":"Trustworthy and professional","is_correct":false},{"id":"d","text":"Neutral and balanced","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES105'), 'multiple_choice', 'What is simultaneous contrast in color perception?', '[{"id":"a","text":"Using two contrasting fonts alongside color","is_correct":false},{"id":"b","text":"The phenomenon where the same color appears different depending on its surrounding colors","is_correct":true},{"id":"c","text":"Displaying two colors at the same time on screen","is_correct":false},{"id":"d","text":"Printing in two color separations","is_correct":false}]', 1, true, true, 3);
