INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'A product manager is often called the CEO of the product because they:', '[{"id":"a","text":"Have authority over all team members","is_correct":false},{"id":"b","text":"Own the product vision and must drive outcomes without direct authority","is_correct":true},{"id":"c","text":"Handle all hiring and firing decisions","is_correct":false},{"id":"d","text":"Write all the code for the product","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'What does the "Jobs to Be Done" (JTBD) framework focus on?', '[{"id":"a","text":"Listing all tasks the product team must complete","is_correct":false},{"id":"b","text":"Understanding the underlying job a customer is trying to get done when they hire a product","is_correct":true},{"id":"c","text":"Defining engineering sprint tasks","is_correct":false},{"id":"d","text":"Tracking customer support tickets","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'What is a minimum viable product (MVP)?', '[{"id":"a","text":"A product with the minimum number of team members to build it","is_correct":false},{"id":"b","text":"The smallest version of a product that delivers value and allows learning from real users","is_correct":true},{"id":"c","text":"A product with no bugs","is_correct":false},{"id":"d","text":"A prototype that only designers can use","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'The RICE scoring framework helps product managers:', '[{"id":"a","text":"Evaluate candidate skills in interviews","is_correct":false},{"id":"b","text":"Prioritize features based on Reach, Impact, Confidence, and Effort","is_correct":true},{"id":"c","text":"Set quarterly financial goals","is_correct":false},{"id":"d","text":"Design user interfaces","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'Which statement best describes product-market fit?', '[{"id":"a","text":"The product has been built on schedule","is_correct":false},{"id":"b","text":"The product satisfies a strong market demand and users would be very disappointed without it","is_correct":true},{"id":"c","text":"The product has been reviewed by a market analyst","is_correct":false},{"id":"d","text":"The marketing campaign has launched","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'What is the difference between output and outcome in product management?', '[{"id":"a","text":"Outputs are teams; outcomes are individuals","is_correct":false},{"id":"b","text":"Outputs are features shipped; outcomes are the measurable changes in user behavior or business metrics","is_correct":true},{"id":"c","text":"Outputs are designs; outcomes are the code written","is_correct":false},{"id":"d","text":"They mean the same thing","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'A common anti-pattern in product management is:', '[{"id":"a","text":"Talking to users regularly","is_correct":false},{"id":"b","text":"Focusing on outcomes over outputs","is_correct":false},{"id":"c","text":"Building features based on the loudest stakeholder voice without user validation","is_correct":true},{"id":"d","text":"Running experiments before shipping","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'What is the purpose of a product discovery phase?', '[{"id":"a","text":"To write code for new features","is_correct":false},{"id":"b","text":"To design the brand identity","is_correct":false},{"id":"c","text":"To determine what problems to solve and validate solutions before building","is_correct":true},{"id":"d","text":"To present the finished product to investors","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'In the MoSCoW prioritization method, what does "S" stand for?', '[{"id":"a","text":"Scheduled","is_correct":false},{"id":"b","text":"Should have","is_correct":true},{"id":"c","text":"Stakeholder-approved","is_correct":false},{"id":"d","text":"Secondary feature","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'Opportunity sizing in product management helps a team:', '[{"id":"a","text":"Estimate the market potential and impact of solving a problem","is_correct":true},{"id":"b","text":"Calculate engineering hours needed","is_correct":false},{"id":"c","text":"Write job descriptions","is_correct":false},{"id":"d","text":"Determine which programming language to use","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'A north star metric is best defined as:', '[{"id":"a","text":"The metric that best captures the value delivered to users and correlates with business success","is_correct":true},{"id":"b","text":"The total revenue of a company","is_correct":false},{"id":"c","text":"The number of bugs fixed per sprint","is_correct":false},{"id":"d","text":"The team velocity in story points","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'When is it appropriate to kill a product feature?', '[{"id":"a","text":"Whenever the engineering team requests it","is_correct":false},{"id":"b","text":"When data consistently shows it adds no user value and increases maintenance burden","is_correct":true},{"id":"c","text":"After one week of low usage","is_correct":false},{"id":"d","text":"Never — shipped features should always remain","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'Which of the following is the best description of a product vision?', '[{"id":"a","text":"A list of all features to be built in the next quarter","is_correct":false},{"id":"b","text":"An inspiring long-term description of the change the product will create in the world","is_correct":true},{"id":"c","text":"The projected revenue for next year","is_correct":false},{"id":"d","text":"The technical architecture plan","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'What is a user story?', '[{"id":"a","text":"A technical specification for a database schema","is_correct":false},{"id":"b","text":"A short, user-centered description of a feature from the perspective of the person using it","is_correct":true},{"id":"c","text":"A marketing testimonial","is_correct":false},{"id":"d","text":"A bug report submitted by a user","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'Continuous discovery refers to the practice of:', '[{"id":"a","text":"Running weekly sprints without stopping","is_correct":false},{"id":"b","text":"Regularly engaging with customers to understand their needs throughout product development","is_correct":true},{"id":"c","text":"Continuously deploying code to production","is_correct":false},{"id":"d","text":"Discovering new employees to hire","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'What makes a good product hypothesis?', '[{"id":"a","text":"It is untestable and aspirational","is_correct":false},{"id":"b","text":"It is specific, measurable, and can be validated or invalidated with evidence","is_correct":true},{"id":"c","text":"It is approved by the CEO","is_correct":false},{"id":"d","text":"It describes the technical implementation in detail","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'What does "build-measure-learn" refer to in Lean product development?', '[{"id":"a","text":"Hiring a team, measuring their performance, and learning from reviews","is_correct":false},{"id":"b","text":"The iterative loop of shipping a small change, measuring results, and learning to guide next steps","is_correct":true},{"id":"c","text":"Building the full product, measuring load time, and learning to optimize","is_correct":false},{"id":"d","text":"A project management certification process","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'The Kano model classifies features into categories including:', '[{"id":"a","text":"Must-haves, performance features, and delighters","is_correct":true},{"id":"b","text":"Frontend, backend, and database features","is_correct":false},{"id":"c","text":"Free, freemium, and premium features","is_correct":false},{"id":"d","text":"Quick wins, big bets, and moonshots","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM101'), 'multiple_choice', 'Why should product managers avoid the feature factory trap?', '[{"id":"a","text":"Features are expensive to build","is_correct":false},{"id":"b","text":"Shipping features without validating outcomes leads to a product that grows in complexity but not in value","is_correct":true},{"id":"c","text":"Features require design approval","is_correct":false},{"id":"d","text":"Too many features make the codebase hard to test","is_correct":false}]', 1, true, true, 3);
