INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'The Agile Manifesto values individuals and interactions over:', '[{"id":"a","text":"User research","is_correct":false},{"id":"b","text":"Processes and tools","is_correct":true},{"id":"c","text":"Sprint planning","is_correct":false},{"id":"d","text":"Stakeholder management","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'In Scrum, what is a Sprint?', '[{"id":"a","text":"A type of bug fix deployment","is_correct":false},{"id":"b","text":"A time-boxed iteration during which a team delivers a potentially shippable increment","is_correct":true},{"id":"c","text":"A performance review cycle","is_correct":false},{"id":"d","text":"A design review meeting","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'Who is responsible for maximizing product value in Scrum?', '[{"id":"a","text":"The Scrum Master","is_correct":false},{"id":"b","text":"The Development Team","is_correct":false},{"id":"c","text":"The Product Owner","is_correct":true},{"id":"d","text":"The Stakeholders","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What is the product backlog?', '[{"id":"a","text":"A list of all known bugs in the product","is_correct":false},{"id":"b","text":"An ordered list of everything that might be needed in the product","is_correct":true},{"id":"c","text":"A record of completed features","is_correct":false},{"id":"d","text":"The team capacity plan","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'The daily standup meeting in Scrum is typically limited to:', '[{"id":"a","text":"One hour","is_correct":false},{"id":"b","text":"Fifteen minutes","is_correct":true},{"id":"c","text":"Thirty minutes","is_correct":false},{"id":"d","text":"Two hours","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What is the purpose of a Sprint Retrospective?', '[{"id":"a","text":"To plan the next sprint backlog","is_correct":false},{"id":"b","text":"To demonstrate work to stakeholders","is_correct":false},{"id":"c","text":"To reflect on team processes and identify improvements","is_correct":true},{"id":"d","text":"To groom the product backlog","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'Kanban is primarily focused on:', '[{"id":"a","text":"Fixed-length sprints","is_correct":false},{"id":"b","text":"Visualizing work and limiting work in progress","is_correct":true},{"id":"c","text":"Detailed upfront planning","is_correct":false},{"id":"d","text":"Role separation between developers and testers","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What does WIP limit mean in Kanban?', '[{"id":"a","text":"Work in Progress limit — a constraint on how many items can be in a given stage at once","is_correct":true},{"id":"b","text":"Weekly Iteration Plan","is_correct":false},{"id":"c","text":"Work Item Priority level","is_correct":false},{"id":"d","text":"Waterfall Integration Point","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'A Scrum Master is responsible for:', '[{"id":"a","text":"Writing user stories","is_correct":false},{"id":"b","text":"Removing impediments and coaching the team on Scrum practices","is_correct":true},{"id":"c","text":"Managing the product roadmap","is_correct":false},{"id":"d","text":"Approving code releases","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What is velocity in Scrum?', '[{"id":"a","text":"The speed of the internet connection used by the team","is_correct":false},{"id":"b","text":"The amount of work a team completes in a sprint, typically measured in story points","is_correct":true},{"id":"c","text":"The rate at which bugs are fixed","is_correct":false},{"id":"d","text":"The number of sprints per quarter","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What is the definition of done (DoD) in Scrum?', '[{"id":"a","text":"A checklist of conditions that must be met before a backlog item is considered complete","is_correct":true},{"id":"b","text":"The final product launch criteria","is_correct":false},{"id":"c","text":"A performance review rubric","is_correct":false},{"id":"d","text":"The sprint goal statement","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What happens during Sprint Planning?', '[{"id":"a","text":"The team reflects on what went well and what to improve","is_correct":false},{"id":"b","text":"Stakeholders review the completed work","is_correct":false},{"id":"c","text":"The team selects backlog items for the sprint and creates a plan to deliver them","is_correct":true},{"id":"d","text":"The Scrum Master assigns tasks to developers","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'Which Agile value prioritizes responding to change over following a plan?', '[{"id":"a","text":"Working software over comprehensive documentation","is_correct":false},{"id":"b","text":"Customer collaboration over contract negotiation","is_correct":false},{"id":"c","text":"Responding to change over following a plan","is_correct":true},{"id":"d","text":"Individuals over processes","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What is "technical debt" in Agile teams?', '[{"id":"a","text":"Money owed to software vendors","is_correct":false},{"id":"b","text":"The accumulated cost of shortcuts and suboptimal decisions in code that must eventually be addressed","is_correct":true},{"id":"c","text":"The backlog of unresolved customer complaints","is_correct":false},{"id":"d","text":"Hours spent on training and upskilling","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'SAFe (Scaled Agile Framework) is used primarily for:', '[{"id":"a","text":"Small teams with fewer than five members","is_correct":false},{"id":"b","text":"Applying Agile principles across large enterprises with multiple teams","is_correct":true},{"id":"c","text":"Running design sprints","is_correct":false},{"id":"d","text":"Managing freelance contractors","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'A "spike" in Agile is:', '[{"id":"a","text":"A sudden increase in sprint velocity","is_correct":false},{"id":"b","text":"A time-boxed research task to reduce uncertainty before committing to a user story","is_correct":true},{"id":"c","text":"A meeting where the team debates priorities","is_correct":false},{"id":"d","text":"A type of retrospective format","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What is backlog refinement (grooming)?', '[{"id":"a","text":"Deleting old completed items from the backlog","is_correct":false},{"id":"b","text":"The ongoing process of reviewing, estimating, and ordering backlog items to keep them ready for sprints","is_correct":true},{"id":"c","text":"Running a design critique of the product backlog","is_correct":false},{"id":"d","text":"Writing acceptance tests for all stories","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'Which of the following is a common Agile anti-pattern?', '[{"id":"a","text":"Holding regular retrospectives","is_correct":false},{"id":"b","text":"Running Scrum-but — following Scrum rules selectively while ignoring inconvenient ones","is_correct":true},{"id":"c","text":"Limiting work in progress","is_correct":false},{"id":"d","text":"Delivering working software frequently","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'Story points are used in Agile to estimate:', '[{"id":"a","text":"Exact hours required to complete a task","is_correct":false},{"id":"b","text":"The relative complexity and effort of a user story","is_correct":true},{"id":"c","text":"Bug severity levels","is_correct":false},{"id":"d","text":"Customer satisfaction scores","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR101'), 'multiple_choice', 'What is the purpose of the Sprint Review?', '[{"id":"a","text":"To plan the next sprint","is_correct":false},{"id":"b","text":"To inspect the increment and adapt the product backlog based on stakeholder feedback","is_correct":true},{"id":"c","text":"To evaluate individual team member performance","is_correct":false},{"id":"d","text":"To refine user stories for the following sprint","is_correct":false}]', 1, true, true, 2);
