INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'What is a grid system in UI design?', '[{"id":"a","text":"A table layout used in spreadsheets","is_correct":false},{"id":"b","text":"A structure of columns and rows that helps organize layout consistently","is_correct":true},{"id":"c","text":"A CSS framework for animations","is_correct":false},{"id":"d","text":"A plugin for design tools","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'What does a gutter refer to in a grid?', '[{"id":"a","text":"The spacing between columns","is_correct":true},{"id":"b","text":"The outer margin of the layout","is_correct":false},{"id":"c","text":"The color of the grid overlay","is_correct":false},{"id":"d","text":"The maximum content width","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'An 8pt spacing system means that:', '[{"id":"a","text":"All spacing values are multiples of 8 pixels","is_correct":true},{"id":"b","text":"The grid has exactly 8 columns","is_correct":false},{"id":"c","text":"Font sizes are multiples of 8","is_correct":false},{"id":"d","text":"The design uses 8 colors only","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Responsive design ensures that a layout:', '[{"id":"a","text":"Loads faster on mobile","is_correct":false},{"id":"b","text":"Adapts to different screen sizes and devices","is_correct":true},{"id":"c","text":"Uses only black and white colors","is_correct":false},{"id":"d","text":"Follows accessibility guidelines automatically","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Which CSS concept is used to implement column-based layouts in modern web design?', '[{"id":"a","text":"CSS Float","is_correct":false},{"id":"b","text":"CSS Grid and Flexbox","is_correct":true},{"id":"c","text":"CSS Animations","is_correct":false},{"id":"d","text":"CSS Filters","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Visual alignment in UI design helps users by:', '[{"id":"a","text":"Making the interface more colorful","is_correct":false},{"id":"b","text":"Creating order, predictability, and easier scanning","is_correct":true},{"id":"c","text":"Increasing the number of elements on screen","is_correct":false},{"id":"d","text":"Adding animation to transitions","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'The max-width of a content container is typically set to:', '[{"id":"a","text":"100px","is_correct":false},{"id":"b","text":"320px","is_correct":false},{"id":"c","text":"1200-1440px depending on the design system","is_correct":true},{"id":"d","text":"4000px","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'White space (negative space) in a layout primarily serves to:', '[{"id":"a","text":"Save printing costs","is_correct":false},{"id":"b","text":"Improve readability and reduce cognitive load","is_correct":true},{"id":"c","text":"Indicate that content is missing","is_correct":false},{"id":"d","text":"Comply with color accessibility rules","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'What is a breakpoint in responsive design?', '[{"id":"a","text":"A point in the code where the app crashes","is_correct":false},{"id":"b","text":"A defined screen width at which the layout changes to accommodate a different device size","is_correct":true},{"id":"c","text":"A color contrast threshold","is_correct":false},{"id":"d","text":"A spacing value used in the 8pt grid","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'The Gestalt principle of proximity states that:', '[{"id":"a","text":"Elements with similar colors are perceived as related","is_correct":false},{"id":"b","text":"Elements close to each other are perceived as related or grouped","is_correct":true},{"id":"c","text":"Elements that are aligned feel more trustworthy","is_correct":false},{"id":"d","text":"Large elements draw attention first","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'What is the primary advantage of using a spacing scale in a design system?', '[{"id":"a","text":"It limits designers to fixed pixel sizes","is_correct":false},{"id":"b","text":"It ensures consistent visual rhythm and harmony across all components","is_correct":true},{"id":"c","text":"It automatically generates CSS","is_correct":false},{"id":"d","text":"It prevents the use of too many colors","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Auto-layout in Figma helps designers by:', '[{"id":"a","text":"Automatically choosing colors","is_correct":false},{"id":"b","text":"Making components resize and reflow based on content dynamically","is_correct":true},{"id":"c","text":"Creating animations between frames","is_correct":false},{"id":"d","text":"Generating lorem ipsum placeholder text","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Which layout pattern is most appropriate for a dashboard with multiple data widgets?', '[{"id":"a","text":"Single column linear layout","is_correct":false},{"id":"b","text":"Masonry or card grid layout","is_correct":true},{"id":"c","text":"Full-page scrollable text layout","is_correct":false},{"id":"d","text":"Accordion-only layout","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Why is a 12-column grid common in web design?', '[{"id":"a","text":"12 is the default in all design tools","is_correct":false},{"id":"b","text":"12 divides evenly into 2, 3, 4, and 6 columns making it highly flexible","is_correct":true},{"id":"c","text":"12 columns is mandated by WCAG","is_correct":false},{"id":"d","text":"It matches the 12-month calendar year","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'The mobile-first design approach means:', '[{"id":"a","text":"Designing only for mobile and ignoring desktop","is_correct":false},{"id":"b","text":"Starting design for the smallest screen and progressively enhancing for larger screens","is_correct":true},{"id":"c","text":"Using app store screenshots as the primary design deliverable","is_correct":false},{"id":"d","text":"Building native mobile apps before web apps","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'The Z-pattern reading layout is best suited for:', '[{"id":"a","text":"Long-form article pages","is_correct":false},{"id":"b","text":"Marketing landing pages with sparse content","is_correct":true},{"id":"c","text":"Data table views","is_correct":false},{"id":"d","text":"Settings pages","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'What is a "card" component pattern in UI design?', '[{"id":"a","text":"A payment input form","is_correct":false},{"id":"b","text":"A contained surface that groups related information and actions together","is_correct":true},{"id":"c","text":"A navigation breadcrumb element","is_correct":false},{"id":"d","text":"A tooltip overlay","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Content shifting during page load (layout shift) is measured by:', '[{"id":"a","text":"Time to First Byte (TTFB)","is_correct":false},{"id":"b","text":"Cumulative Layout Shift (CLS) — a Core Web Vital metric","is_correct":true},{"id":"c","text":"First Contentful Paint (FCP)","is_correct":false},{"id":"d","text":"Largest Contentful Paint (LCP)","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'The F-pattern reading behavior describes how users:', '[{"id":"a","text":"Read every word on a page","is_correct":false},{"id":"b","text":"Scan horizontally across the top then down the left side of content","is_correct":true},{"id":"c","text":"Focus exclusively on images","is_correct":false},{"id":"d","text":"Jump randomly between sections","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES102'), 'multiple_choice', 'Design tokens for spacing allow teams to:', '[{"id":"a","text":"Store spacing values as named variables shared between design and code","is_correct":true},{"id":"b","text":"Limit the number of spacing values in a design","is_correct":false},{"id":"c","text":"Automatically apply spacing to all components","is_correct":false},{"id":"d","text":"Convert designs to CSS automatically","is_correct":false}]', 1, true, true, 3);
