INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Hick''s Law states that:', '[{"id":"a","text":"Larger buttons are always easier to click","is_correct":false},{"id":"b","text":"The time to make a decision increases with the number and complexity of choices","is_correct":true},{"id":"c","text":"Users read from left to right","is_correct":false},{"id":"d","text":"People remember only 7 items at a time","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The anchoring bias in design means users:', '[{"id":"a","text":"Scroll to the bottom of a page before reading","is_correct":false},{"id":"b","text":"Rely heavily on the first piece of information they see when making decisions","is_correct":true},{"id":"c","text":"Prefer anchored navigation menus","is_correct":false},{"id":"d","text":"Ignore all content below the fold","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The Gestalt principle of similarity states that:', '[{"id":"a","text":"Elements that look alike are perceived as belonging to the same group","is_correct":true},{"id":"b","text":"Elements close together are grouped","is_correct":false},{"id":"c","text":"Users prefer symmetric layouts","is_correct":false},{"id":"d","text":"Simple shapes are more memorable","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'What is cognitive load in UX design?', '[{"id":"a","text":"The weight of UI elements on the page","is_correct":false},{"id":"b","text":"The mental effort required to use an interface","is_correct":true},{"id":"c","text":"The loading time of a web page","is_correct":false},{"id":"d","text":"The number of clicks required to complete a task","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Miller''s Law suggests that working memory can hold approximately:', '[{"id":"a","text":"3 items","is_correct":false},{"id":"b","text":"7 plus or minus 2 chunks of information","is_correct":true},{"id":"c","text":"15 items","is_correct":false},{"id":"d","text":"100 items","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The peak-end rule in UX states that users judge an experience based on:', '[{"id":"a","text":"The average of all moments in the experience","is_correct":false},{"id":"b","text":"The most intense moment and the final moment of the experience","is_correct":true},{"id":"c","text":"The first interaction only","is_correct":false},{"id":"d","text":"How long the experience lasted","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Fitts''s Law relates to:', '[{"id":"a","text":"The number of errors a user makes","is_correct":false},{"id":"b","text":"The time required to move to a target based on its size and distance","is_correct":true},{"id":"c","text":"The reading speed of users","is_correct":false},{"id":"d","text":"Font size and legibility","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Social proof in UI design leverages:', '[{"id":"a","text":"Legal terms and conditions","is_correct":false},{"id":"b","text":"The tendency to follow the actions of others to reduce uncertainty","is_correct":true},{"id":"c","text":"Government regulations on design","is_correct":false},{"id":"d","text":"Competitor analysis","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'A mental model is:', '[{"id":"a","text":"A wireframe of a user interface","is_correct":false},{"id":"b","text":"A user''s internal representation of how a system works","is_correct":true},{"id":"c","text":"A database schema","is_correct":false},{"id":"d","text":"A design pattern library","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Scarcity and urgency cues (e.g., "Only 3 left!") work because of:', '[{"id":"a","text":"The sunk cost fallacy","is_correct":false},{"id":"b","text":"Loss aversion — people fear losing more than they desire gaining","is_correct":true},{"id":"c","text":"The mere exposure effect","is_correct":false},{"id":"d","text":"The paradox of choice","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The mere exposure effect means users tend to:', '[{"id":"a","text":"Avoid familiar interface patterns","is_correct":false},{"id":"b","text":"Develop a preference for things they have seen more frequently","is_correct":true},{"id":"c","text":"Trust only new and novel designs","is_correct":false},{"id":"d","text":"Spend less time on familiar websites","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'What is the von Restorff effect?', '[{"id":"a","text":"Items at the end of a list are best remembered","is_correct":false},{"id":"b","text":"An item that stands out from its group is more likely to be remembered","is_correct":true},{"id":"c","text":"Users remember the first item in a list best","is_correct":false},{"id":"d","text":"Repetition increases memory retention","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Dark patterns in UX design are:', '[{"id":"a","text":"Color schemes that use dark backgrounds","is_correct":false},{"id":"b","text":"UI design tricks that deceive users into taking actions they did not intend","is_correct":true},{"id":"c","text":"Accessibility modes for low-light environments","is_correct":false},{"id":"d","text":"Advanced design techniques for expert users","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Progressive disclosure in UX helps reduce cognitive load by:', '[{"id":"a","text":"Hiding all features permanently","is_correct":false},{"id":"b","text":"Showing only the information and options most relevant to the current user action","is_correct":true},{"id":"c","text":"Displaying advanced features to all users from the start","is_correct":false},{"id":"d","text":"Using gradients to reveal content","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The Zeigarnik effect suggests that users:', '[{"id":"a","text":"Remember completed tasks better than incomplete ones","is_correct":false},{"id":"b","text":"Remember incomplete tasks better than completed ones, which can be used for engagement","is_correct":true},{"id":"c","text":"Prefer minimalist designs","is_correct":false},{"id":"d","text":"Avoid multi-step processes","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Chunking information in a UI helps users by:', '[{"id":"a","text":"Hiding content until the user requests it","is_correct":false},{"id":"b","text":"Grouping related items to reduce the burden on working memory","is_correct":true},{"id":"c","text":"Using smaller font sizes","is_correct":false},{"id":"d","text":"Removing all visual hierarchy","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The serial position effect means users best remember:', '[{"id":"a","text":"Items in the middle of a list","is_correct":false},{"id":"b","text":"Items at the beginning (primacy) and end (recency) of a list","is_correct":true},{"id":"c","text":"The most colorful items","is_correct":false},{"id":"d","text":"Only the last item shown","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'Confirmation bias in usability testing means:', '[{"id":"a","text":"Users always agree with the facilitator","is_correct":false},{"id":"b","text":"Researchers may unconsciously interpret results to confirm their existing beliefs","is_correct":true},{"id":"c","text":"Participants confirm they have read the consent form","is_correct":false},{"id":"d","text":"Tests are conducted in a biased lab setting","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The aesthetic-usability effect suggests:', '[{"id":"a","text":"Aesthetic designs always perform better in usability tests","is_correct":false},{"id":"b","text":"Users perceive aesthetically pleasing designs as more usable, even when functionality is the same","is_correct":true},{"id":"c","text":"Ugly designs always have better usability","is_correct":false},{"id":"d","text":"Design aesthetics have no effect on user perception","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES104'), 'multiple_choice', 'The paradox of choice, as studied by Barry Schwartz, implies that:', '[{"id":"a","text":"More choices always lead to greater user satisfaction","is_correct":false},{"id":"b","text":"Too many choices can lead to decision paralysis and lower satisfaction","is_correct":true},{"id":"c","text":"Users prefer no choices at all","is_correct":false},{"id":"d","text":"Choice reduces cognitive load","is_correct":false}]', 1, true, true, 3);
