INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'What is the primary goal of user research?', '[{"id":"a","text":"To test if a product has been built correctly","is_correct":false},{"id":"b","text":"To understand user needs, behaviors, and motivations to inform design and product decisions","is_correct":true},{"id":"c","text":"To write marketing copy","is_correct":false},{"id":"d","text":"To benchmark competitor products","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'Which research method answers the question "Why?"', '[{"id":"a","text":"Quantitative research","is_correct":false},{"id":"b","text":"Qualitative research","is_correct":true},{"id":"c","text":"A/B testing","is_correct":false},{"id":"d","text":"Analytics dashboards","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'An open-ended interview question is one that:', '[{"id":"a","text":"Can be answered with yes or no","is_correct":false},{"id":"b","text":"Invites the participant to share thoughts and experiences freely","is_correct":true},{"id":"c","text":"Has predefined answer choices","is_correct":false},{"id":"d","text":"Leads the participant toward a specific answer","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'A screener in user research is used to:', '[{"id":"a","text":"Filter spam from survey responses","is_correct":false},{"id":"b","text":"Qualify and select appropriate participants for a study","is_correct":true},{"id":"c","text":"Display content based on user role","is_correct":false},{"id":"d","text":"Record screen interactions during testing","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'The recommended sample size for qualitative user interviews to reach saturation is approximately:', '[{"id":"a","text":"100+","is_correct":false},{"id":"b","text":"50","is_correct":false},{"id":"c","text":"5-8 per segment","is_correct":true},{"id":"d","text":"1-2","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'Affinity mapping is a technique used to:', '[{"id":"a","text":"Map user locations geographically","is_correct":false},{"id":"b","text":"Group and cluster qualitative data to identify themes and patterns","is_correct":true},{"id":"c","text":"Create user personas","is_correct":false},{"id":"d","text":"Score survey responses numerically","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'What is a leading question in user research?', '[{"id":"a","text":"The first question in an interview guide","is_correct":false},{"id":"b","text":"A question that suggests the desired answer and introduces bias","is_correct":true},{"id":"c","text":"A question about the user''s leadership experience","is_correct":false},{"id":"d","text":"A question that opens the interview","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'The "5 Whys" technique helps researchers:', '[{"id":"a","text":"Create five survey questions","is_correct":false},{"id":"b","text":"Get to the root cause of a problem by asking why repeatedly","is_correct":true},{"id":"c","text":"Conduct five rounds of usability testing","is_correct":false},{"id":"d","text":"Identify five user personas","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'Contextual inquiry involves:', '[{"id":"a","text":"Observing and interviewing users in their natural environment while they work","is_correct":true},{"id":"b","text":"Sending users an online survey","is_correct":false},{"id":"c","text":"Interviewing users in a usability lab only","is_correct":false},{"id":"d","text":"Analyzing server logs for user behavior","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'What is the Likert scale used for in surveys?', '[{"id":"a","text":"Measuring page load time","is_correct":false},{"id":"b","text":"Capturing the degree of agreement or disagreement with a statement","is_correct":true},{"id":"c","text":"Ranking features by priority","is_correct":false},{"id":"d","text":"Selecting user demographics","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'What differentiates generative research from evaluative research?', '[{"id":"a","text":"Generative uses numbers; evaluative uses words","is_correct":false},{"id":"b","text":"Generative discovers problems and opportunities; evaluative tests existing solutions","is_correct":true},{"id":"c","text":"Generative is done after launch; evaluative before launch","is_correct":false},{"id":"d","text":"They are the same type of research","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'The NPS (Net Promoter Score) survey asks:', '[{"id":"a","text":"How satisfied are you with our product?","is_correct":false},{"id":"b","text":"How likely are you to recommend our product to a friend or colleague?","is_correct":true},{"id":"c","text":"How many times per week do you use our product?","is_correct":false},{"id":"d","text":"What is your biggest frustration with our product?","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'A research insight differs from raw observation because:', '[{"id":"a","text":"Insights are derived from a single user and observations from many","is_correct":false},{"id":"b","text":"An insight is an interpretation of what the data means and why it matters, not just what happened","is_correct":true},{"id":"c","text":"Insights come from analytics; observations from interviews","is_correct":false},{"id":"d","text":"They are the same thing","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'What is the risk of only interviewing existing customers for user research?', '[{"id":"a","text":"Existing customers provide too much data","is_correct":false},{"id":"b","text":"You may miss insights from potential users or churned users who represent unmet needs","is_correct":true},{"id":"c","text":"Existing customers refuse to participate in interviews","is_correct":false},{"id":"d","text":"Their feedback is always positive and therefore unreliable","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'Triangulation in research refers to:', '[{"id":"a","text":"Using three participants per session","is_correct":false},{"id":"b","text":"Using multiple research methods to validate findings and reduce bias","is_correct":true},{"id":"c","text":"Creating a triangle diagram of user segments","is_correct":false},{"id":"d","text":"Interviewing users three times","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'What is diary study research?', '[{"id":"a","text":"A method where researchers write daily notes about users","is_correct":false},{"id":"b","text":"A longitudinal method where participants self-report experiences over time","is_correct":true},{"id":"c","text":"A survey sent once a week","is_correct":false},{"id":"d","text":"A competitive analysis technique","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'How many participants are typically needed for quantitative research to be statistically significant?', '[{"id":"a","text":"5-8","is_correct":false},{"id":"b","text":"At least 100, depending on the confidence level and margin of error","is_correct":true},{"id":"c","text":"Exactly 30","is_correct":false},{"id":"d","text":"Any number works equally well","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'The think-aloud protocol asks research participants to:', '[{"id":"a","text":"Write their thoughts on paper silently","is_correct":false},{"id":"b","text":"Verbalize their thoughts, feelings, and reasoning while completing tasks","is_correct":true},{"id":"c","text":"Rate tasks on a scale after completing them","is_correct":false},{"id":"d","text":"Complete tasks as fast as possible without speaking","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'Survivorship bias in user research happens when:', '[{"id":"a","text":"Only users who survived a product redesign are interviewed","is_correct":false},{"id":"b","text":"Conclusions are drawn only from users who are still using the product, ignoring those who churned","is_correct":true},{"id":"c","text":"Users who participated in previous studies are excluded","is_correct":false},{"id":"d","text":"Research is conducted only during product launches","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM102'), 'multiple_choice', 'A research repository helps teams by:', '[{"id":"a","text":"Storing all product code in one place","is_correct":false},{"id":"b","text":"Centralizing research findings so teams can build on past insights instead of repeating studies","is_correct":true},{"id":"c","text":"Automating user interview scheduling","is_correct":false},{"id":"d","text":"Generating AI-based user personas","is_correct":false}]', 1, true, true, 2);
