INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'In sprint planning, the sprint goal should be:', '[{"id":"a","text":"A list of all tasks assigned to each team member","is_correct":false},{"id":"b","text":"A concise objective that provides focus and direction for the sprint","is_correct":true},{"id":"c","text":"An estimate of total story points","is_correct":false},{"id":"d","text":"A copy of the product vision","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What is the recommended maximum sprint length in Scrum?', '[{"id":"a","text":"One week","is_correct":false},{"id":"b","text":"One month","is_correct":true},{"id":"c","text":"Six weeks","is_correct":false},{"id":"d","text":"Three months","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'During a daily standup, team members should address:', '[{"id":"a","text":"What they did yesterday, what they plan today, and any blockers","is_correct":true},{"id":"b","text":"A full status report for the sprint","is_correct":false},{"id":"c","text":"Feature requests from stakeholders","is_correct":false},{"id":"d","text":"Code review comments","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'Planning Poker is used in Scrum to:', '[{"id":"a","text":"Gamify the retrospective","is_correct":false},{"id":"b","text":"Estimate story points through team consensus using hidden cards revealed simultaneously","is_correct":true},{"id":"c","text":"Prioritize the product backlog","is_correct":false},{"id":"d","text":"Run a competitive team exercise","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'A user story follows the format:', '[{"id":"a","text":"As a developer, I want to build X so I can meet the deadline","is_correct":false},{"id":"b","text":"As a [type of user], I want [goal] so that [benefit]","is_correct":true},{"id":"c","text":"Feature: X. Acceptance: Y. Priority: Z","is_correct":false},{"id":"d","text":"Task: X. Assignee: Y. Duration: Z hours","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What happens if the team cannot complete all sprint backlog items by the sprint end?', '[{"id":"a","text":"The sprint is extended until all items are done","is_correct":false},{"id":"b","text":"Incomplete items are returned to the product backlog for future prioritization","is_correct":true},{"id":"c","text":"The team is penalized in their performance review","is_correct":false},{"id":"d","text":"The Scrum Master must finish the remaining work","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'An impediment in Scrum is:', '[{"id":"a","text":"A feature that is too complex to build","is_correct":false},{"id":"b","text":"Any obstacle that prevents the team from progressing on their work","is_correct":true},{"id":"c","text":"A stakeholder who disagrees with the roadmap","is_correct":false},{"id":"d","text":"A low-priority backlog item","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What is the recommended team size for a Scrum development team?', '[{"id":"a","text":"1-2 people","is_correct":false},{"id":"b","text":"10-20 people","is_correct":false},{"id":"c","text":"3-9 people","is_correct":true},{"id":"d","text":"50+ people","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'Acceptance criteria in a user story define:', '[{"id":"a","text":"The technical stack to be used","is_correct":false},{"id":"b","text":"The specific conditions that must be met for the story to be accepted as done","is_correct":true},{"id":"c","text":"Who will test the feature","is_correct":false},{"id":"d","text":"The story point estimate","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'In a retrospective using the Start/Stop/Continue format, "Start" refers to:', '[{"id":"a","text":"Beginning the next sprint","is_correct":false},{"id":"b","text":"New practices the team should adopt","is_correct":true},{"id":"c","text":"Restarting a failed project","is_correct":false},{"id":"d","text":"Items to add to the sprint backlog","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What is a burndown chart used for in Scrum?', '[{"id":"a","text":"Tracking team happiness over the sprint","is_correct":false},{"id":"b","text":"Visualizing the remaining work versus time in a sprint","is_correct":true},{"id":"c","text":"Logging bugs by severity","is_correct":false},{"id":"d","text":"Recording stakeholder feedback","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'Which of the following best describes an effective sprint demo?', '[{"id":"a","text":"A slide deck explaining what was planned","is_correct":false},{"id":"b","text":"A live demonstration of working software to stakeholders for feedback","is_correct":true},{"id":"c","text":"A report of story points completed","is_correct":false},{"id":"d","text":"A presentation of the team''s technical architecture","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What is the consequence of skipping sprint retrospectives?', '[{"id":"a","text":"The team saves time","is_correct":false},{"id":"b","text":"The team misses opportunities to identify and address recurring problems, leading to stagnation","is_correct":true},{"id":"c","text":"The product backlog grows faster","is_correct":false},{"id":"d","text":"Stakeholder satisfaction increases","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'Interrupting a sprint mid-way with new urgent requirements is best handled by:', '[{"id":"a","text":"Immediately adding the requirement to the current sprint","is_correct":false},{"id":"b","text":"Evaluating the urgency; if critical, considering cancelling the sprint; otherwise adding to the backlog","is_correct":true},{"id":"c","text":"Ignoring the requirement until the next quarter","is_correct":false},{"id":"d","text":"Assigning it to the Scrum Master","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What is the role of a Scrum Master in conflict between team members?', '[{"id":"a","text":"To decide who is right and enforce the decision","is_correct":false},{"id":"b","text":"To coach the team in conflict resolution and help create a safe environment for open discussion","is_correct":true},{"id":"c","text":"To escalate the conflict to HR immediately","is_correct":false},{"id":"d","text":"To remove the underperforming member from the team","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'In remote Scrum teams, what is most important for maintaining team cohesion?', '[{"id":"a","text":"Sending daily written reports","is_correct":false},{"id":"b","text":"Regular video ceremonies, asynchronous documentation, and clear communication norms","is_correct":true},{"id":"c","text":"Working only in the same time zone","is_correct":false},{"id":"d","text":"Using only one collaboration tool","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What does it mean to "refine" a user story?', '[{"id":"a","text":"To remove it from the backlog","is_correct":false},{"id":"b","text":"To clarify details, add acceptance criteria, and estimate effort so it is ready for a sprint","is_correct":true},{"id":"c","text":"To rewrite it in technical language","is_correct":false},{"id":"d","text":"To approve it for production","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'The INVEST acronym for user stories stands for:', '[{"id":"a","text":"Independent, Negotiable, Valuable, Estimable, Small, Testable","is_correct":true},{"id":"b","text":"Integrated, Notable, Verified, Essential, Significant, Tracked","is_correct":false},{"id":"c","text":"Independent, Notable, Validated, Effective, Simple, Tracked","is_correct":false},{"id":"d","text":"Iterative, Negotiable, Versioned, Executable, Stable, Tested","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What is a common sign that a Scrum team is not truly self-organizing?', '[{"id":"a","text":"The team holds daily standups","is_correct":false},{"id":"b","text":"Tasks are always assigned by the Scrum Master or manager rather than picked up by the team","is_correct":true},{"id":"c","text":"The team estimates in story points","is_correct":false},{"id":"d","text":"The team uses a Kanban board","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SCR102'), 'multiple_choice', 'What is the primary output of sprint planning?', '[{"id":"a","text":"A slide deck for stakeholders","is_correct":false},{"id":"b","text":"A sprint backlog with a clear sprint goal and plan for delivery","is_correct":true},{"id":"c","text":"A updated product roadmap","is_correct":false},{"id":"d","text":"A list of new features requested by customers","is_correct":false}]', 1, true, true, 2);
