INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'What does UX stand for?', '[{"id":"a","text":"User Execution","is_correct":false},{"id":"b","text":"User Experience","is_correct":true},{"id":"c","text":"Universal Exchange","is_correct":false},{"id":"d","text":"Unified Extension","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'Information architecture in UX is concerned with:', '[{"id":"a","text":"The visual appearance of the interface","is_correct":false},{"id":"b","text":"How content is organized and structured to support usability","is_correct":true},{"id":"c","text":"Database design","is_correct":false},{"id":"d","text":"Animation and transitions","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'A wireframe is best described as:', '[{"id":"a","text":"A high-fidelity visual design","is_correct":false},{"id":"b","text":"A low-fidelity blueprint showing structure and layout without visual details","is_correct":true},{"id":"c","text":"A fully coded prototype","is_correct":false},{"id":"d","text":"A user research report","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'The Double Diamond design process includes which four phases?', '[{"id":"a","text":"Research, Analysis, Design, Test","is_correct":false},{"id":"b","text":"Discover, Define, Develop, Deliver","is_correct":true},{"id":"c","text":"Empathize, Define, Ideate, Prototype","is_correct":false},{"id":"d","text":"Plan, Build, Ship, Measure","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'What is the purpose of a UX brief?', '[{"id":"a","text":"To document all design decisions made during the project","is_correct":false},{"id":"b","text":"To define the scope, goals, constraints, and target users for a design project","is_correct":true},{"id":"c","text":"To present finished designs to stakeholders","is_correct":false},{"id":"d","text":"To list the tools and technologies to be used","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'Card sorting in UX research helps with:', '[{"id":"a","text":"Testing visual design preferences","is_correct":false},{"id":"b","text":"Understanding how users categorize and label information","is_correct":true},{"id":"c","text":"Measuring task completion time","is_correct":false},{"id":"d","text":"Generating product names","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'Lean UX emphasizes:', '[{"id":"a","text":"Extensive upfront documentation before any design","is_correct":false},{"id":"b","text":"Rapid iteration, cross-functional collaboration, and validating assumptions quickly","is_correct":true},{"id":"c","text":"Waterfall delivery of complete design packages","is_correct":false},{"id":"d","text":"High-fidelity prototypes before any research","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'A task flow diagram shows:', '[{"id":"a","text":"The visual color scheme for the app","is_correct":false},{"id":"b","text":"The steps a user takes to complete a specific task within a product","is_correct":true},{"id":"c","text":"The database relationships","is_correct":false},{"id":"d","text":"The business revenue model","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'What is the key difference between UX and UI design?', '[{"id":"a","text":"UX is for mobile; UI is for desktop","is_correct":false},{"id":"b","text":"UX focuses on the overall experience and usability; UI focuses on visual design and interface elements","is_correct":true},{"id":"c","text":"UX is done by engineers; UI by designers","is_correct":false},{"id":"d","text":"They are identical disciplines","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'Heuristic evaluation in UX involves:', '[{"id":"a","text":"Testing with real users in a lab","is_correct":false},{"id":"b","text":"Expert reviewers evaluating an interface against established usability principles","is_correct":true},{"id":"c","text":"Using analytics to measure user behavior","is_correct":false},{"id":"d","text":"Running A/B tests on two design variants","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'What are Nielsen''s 10 usability heuristics primarily used for?', '[{"id":"a","text":"Writing user stories","is_correct":false},{"id":"b","text":"Evaluating interface design against proven principles of good usability","is_correct":true},{"id":"c","text":"Defining accessibility requirements","is_correct":false},{"id":"d","text":"Conducting user interviews","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES201'), 'multiple_choice', 'What does "visibility of system status" mean as a usability heuristic?', '[{"id":"a","text":"The interface should be visible on all screen sizes","is_correct":false},{"id":"b","text":"The system should always keep users informed about what is happening through appropriate feedback","is_correct":true},{"id":"c","text":"All UI elements must be visible without scrolling","is_correct":false},{"id":"d","text":"The app should display a system health dashboard","is_correct":false}]', 1, true, true, 2);
