INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'A PRD (Product Requirements Document) primarily serves to:', '[{"id":"a","text":"Document the technical architecture","is_correct":false},{"id":"b","text":"Define what to build, why, and for whom, aligning teams around a shared understanding","is_correct":true},{"id":"c","text":"Replace daily standups","is_correct":false},{"id":"d","text":"Serve as the final project invoice","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Which of the following is NOT typically included in a PRD?', '[{"id":"a","text":"Problem statement","is_correct":false},{"id":"b","text":"Success metrics","is_correct":false},{"id":"c","text":"Database schema diagrams","is_correct":true},{"id":"d","text":"Scope and out-of-scope items","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Acceptance criteria should be written in a way that:', '[{"id":"a","text":"Describes the exact code implementation","is_correct":false},{"id":"b","text":"Can be objectively verified as either met or not met","is_correct":true},{"id":"c","text":"Is vague enough to give developers flexibility","is_correct":false},{"id":"d","text":"Is only readable by the QA team","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Gherkin syntax (Given/When/Then) is used to write:', '[{"id":"a","text":"Database queries","is_correct":false},{"id":"b","text":"Behavior-driven acceptance criteria","is_correct":true},{"id":"c","text":"Marketing copy","is_correct":false},{"id":"d","text":"Sprint planning agendas","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'What is a functional requirement?', '[{"id":"a","text":"A requirement about system performance","is_correct":false},{"id":"b","text":"A requirement describing what the system should do","is_correct":true},{"id":"c","text":"A requirement about team structure","is_correct":false},{"id":"d","text":"A technical architecture decision","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'What is a non-functional requirement?', '[{"id":"a","text":"A requirement that has been rejected by stakeholders","is_correct":false},{"id":"b","text":"A requirement that defines quality attributes like performance, security, or scalability","is_correct":true},{"id":"c","text":"A requirement outside the product scope","is_correct":false},{"id":"d","text":"A requirement only relevant to design","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'In requirements writing, "out of scope" means:', '[{"id":"a","text":"Features that are currently broken","is_correct":false},{"id":"b","text":"Items explicitly not included in the current initiative to manage expectations","is_correct":true},{"id":"c","text":"Requirements that need more research","is_correct":false},{"id":"d","text":"Competitor features to avoid","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'A well-written user story should be:', '[{"id":"a","text":"As long and detailed as possible","is_correct":false},{"id":"b","text":"Independent, negotiable, valuable, estimable, small, and testable","is_correct":true},{"id":"c","text":"Written only by engineers","is_correct":false},{"id":"d","text":"Identical to a bug report","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'What is an epic in product requirements?', '[{"id":"a","text":"A very important bug","is_correct":false},{"id":"b","text":"A large body of work that can be broken down into smaller user stories","is_correct":true},{"id":"c","text":"A product launch event","is_correct":false},{"id":"d","text":"A list of all product features","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Why is it important to document assumptions in a PRD?', '[{"id":"a","text":"To blame team members if the project fails","is_correct":false},{"id":"b","text":"To surface potentially incorrect beliefs early so they can be validated or invalidated before building","is_correct":true},{"id":"c","text":"Because assumptions are always true","is_correct":false},{"id":"d","text":"To comply with regulatory requirements","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Edge cases in requirements are important because:', '[{"id":"a","text":"They are the most common scenarios","is_correct":false},{"id":"b","text":"They represent uncommon but valid situations that the product must handle correctly","is_correct":true},{"id":"c","text":"They are always out of scope","is_correct":false},{"id":"d","text":"Only QA teams need to think about them","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'What makes a requirements document "living"?', '[{"id":"a","text":"It uses animated diagrams","is_correct":false},{"id":"b","text":"It is continuously updated as new information, decisions, and changes emerge","is_correct":true},{"id":"c","text":"It is printed on recycled paper","is_correct":false},{"id":"d","text":"It includes real-time analytics data","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'The primary audience for a PRD is:', '[{"id":"a","text":"Investors and board members only","is_correct":false},{"id":"b","text":"All cross-functional team members including design, engineering, and QA","is_correct":true},{"id":"c","text":"End users of the product","is_correct":false},{"id":"d","text":"The legal team","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Which of the following is a sign of poorly written requirements?', '[{"id":"a","text":"They include measurable success criteria","is_correct":false},{"id":"b","text":"They use ambiguous language like fast, easy, or user-friendly without definition","is_correct":true},{"id":"c","text":"They specify the target user","is_correct":false},{"id":"d","text":"They include edge cases","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'What is the difference between a task and a user story?', '[{"id":"a","text":"Tasks are for designers; user stories are for developers","is_correct":false},{"id":"b","text":"A user story describes a user goal; a task is a specific piece of work needed to achieve that goal","is_correct":true},{"id":"c","text":"They are interchangeable terms","is_correct":false},{"id":"d","text":"Tasks are larger than user stories","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Requirement traceability means:', '[{"id":"a","text":"Requirements that can be found easily in a document","is_correct":false},{"id":"b","text":"The ability to link requirements to their origin, design decisions, and test cases","is_correct":true},{"id":"c","text":"Tracking requirement changes via email","is_correct":false},{"id":"d","text":"Translating requirements into multiple languages","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'What is requirements creep?', '[{"id":"a","text":"When bugs slowly appear in a feature over time","is_correct":false},{"id":"b","text":"The uncontrolled expansion of project scope through continuous addition of new requirements","is_correct":true},{"id":"c","text":"When requirements are written too slowly","is_correct":false},{"id":"d","text":"A gradual reduction in requirement quality","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'When writing requirements, specifying "why" alongside "what" is important because:', '[{"id":"a","text":"It satisfies legal documentation requirements","is_correct":false},{"id":"b","text":"Understanding the intent helps teams make better decisions when implementation details change","is_correct":true},{"id":"c","text":"It prevents engineers from asking questions","is_correct":false},{"id":"d","text":"Stakeholders prefer longer documents","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'Success metrics in a PRD should be:', '[{"id":"a","text":"Aspirational but not measurable","is_correct":false},{"id":"b","text":"Specific, measurable, and tied to business or user outcomes","is_correct":true},{"id":"c","text":"Defined by the engineering team only","is_correct":false},{"id":"d","text":"Set after the product launches","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM201'), 'multiple_choice', 'A dependency in product requirements refers to:', '[{"id":"a","text":"A feature that users want but have not requested","is_correct":false},{"id":"b","text":"A constraint where one piece of work relies on another being completed first","is_correct":true},{"id":"c","text":"A third-party library used by the engineering team","is_correct":false},{"id":"d","text":"An optional requirement","is_correct":false}]', 1, true, true, 2);
