INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'DAU/MAU ratio is used to measure:', '[{"id":"a","text":"Database query performance","is_correct":false},{"id":"b","text":"Product stickiness — how often active users return within a month","is_correct":true},{"id":"c","text":"Download to activation rate","is_correct":false},{"id":"d","text":"Design asset usage","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'A funnel analysis in product analytics helps you:', '[{"id":"a","text":"Visualize the company org chart","is_correct":false},{"id":"b","text":"Identify where users drop off in a multi-step process","is_correct":true},{"id":"c","text":"Track marketing spend","is_correct":false},{"id":"d","text":"Measure page load speed","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Retention rate is defined as the percentage of users who:', '[{"id":"a","text":"Downloaded the app","is_correct":false},{"id":"b","text":"Return and use the product in a subsequent period after their first use","is_correct":true},{"id":"c","text":"Referred other users","is_correct":false},{"id":"d","text":"Upgraded to a premium plan","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'An event in product analytics refers to:', '[{"id":"a","text":"A company conference","is_correct":false},{"id":"b","text":"A specific user action tracked in the product such as clicking a button or completing a step","is_correct":true},{"id":"c","text":"A server error","is_correct":false},{"id":"d","text":"A billing transaction","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'The AARRR metrics framework stands for:', '[{"id":"a","text":"Acquire, Activate, Revenue, Retain, Refer","is_correct":true},{"id":"b","text":"Analytics, Action, Results, Reports, Revenue","is_correct":false},{"id":"c","text":"Analyze, Automate, Run, Review, Report","is_correct":false},{"id":"d","text":"Attention, Attraction, Retention, Revenue, Referral","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'A cohort analysis groups users by:', '[{"id":"a","text":"Their geographic location","is_correct":false},{"id":"b","text":"The time period when they first performed an action such as signing up","is_correct":true},{"id":"c","text":"Their subscription plan","is_correct":false},{"id":"d","text":"Their device type","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'What is the activation metric in the AARRR framework?', '[{"id":"a","text":"The number of app downloads","is_correct":false},{"id":"b","text":"The moment a user first experiences the core value of the product","is_correct":true},{"id":"c","text":"The revenue generated per user","is_correct":false},{"id":"d","text":"The number of referrals made","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Vanity metrics are dangerous in product analytics because:', '[{"id":"a","text":"They are too expensive to measure","is_correct":false},{"id":"b","text":"They look impressive but do not correlate to actual business outcomes or user value","is_correct":true},{"id":"c","text":"They are difficult to visualize","is_correct":false},{"id":"d","text":"They require too much data storage","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Churn rate measures:', '[{"id":"a","text":"The rate at which servers process requests","is_correct":false},{"id":"b","text":"The percentage of customers who stop using or cancel the product over a given period","is_correct":true},{"id":"c","text":"The speed of content delivery","is_correct":false},{"id":"d","text":"The rate of new feature adoption","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Session duration as a product metric can be misleading because:', '[{"id":"a","text":"It is hard to track accurately","is_correct":false},{"id":"b","text":"Longer sessions might indicate confusion or frustration rather than engagement","is_correct":true},{"id":"c","text":"It can only be measured on desktop","is_correct":false},{"id":"d","text":"GDPR restricts session tracking","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Customer Lifetime Value (LTV) is calculated as approximately:', '[{"id":"a","text":"Monthly revenue divided by total customers","is_correct":false},{"id":"b","text":"Average revenue per user multiplied by average customer lifespan","is_correct":true},{"id":"c","text":"Total revenue divided by churn rate","is_correct":false},{"id":"d","text":"Number of active users times conversion rate","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'What is a north star metric?', '[{"id":"a","text":"A single metric that tells the status of the server","is_correct":false},{"id":"b","text":"The single most important metric that best reflects the core value delivered to customers","is_correct":true},{"id":"c","text":"The highest revenue metric","is_correct":false},{"id":"d","text":"The metric tracked by the CEO","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Why is it important to track leading indicators rather than only lagging indicators?', '[{"id":"a","text":"Leading indicators are easier to measure","is_correct":false},{"id":"b","text":"Leading indicators predict future outcomes allowing teams to act before problems become visible in lagging metrics","is_correct":true},{"id":"c","text":"Lagging indicators are never useful","is_correct":false},{"id":"d","text":"Leading indicators satisfy regulatory requirements","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'What does MAU stand for in analytics?', '[{"id":"a","text":"Maximum Allowable Users","is_correct":false},{"id":"b","text":"Monthly Active Users","is_correct":true},{"id":"c","text":"Multi-Attribute Utilization","is_correct":false},{"id":"d","text":"Managed Acquisition Units","is_correct":false}]', 1, true, true, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Which analytics tool is most commonly used for product event tracking?', '[{"id":"a","text":"Photoshop","is_correct":false},{"id":"b","text":"Mixpanel or Amplitude","is_correct":true},{"id":"c","text":"Jira","is_correct":false},{"id":"d","text":"Figma","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'What does it mean when a retention curve flattens?', '[{"id":"a","text":"Users are churning at an accelerating rate","is_correct":false},{"id":"b","text":"A core group of users has found long-term value and continue using the product","is_correct":true},{"id":"c","text":"The product has stopped growing","is_correct":false},{"id":"d","text":"The analytics tracking has a bug","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Instrumentation in product analytics refers to:', '[{"id":"a","text":"Adding musical instruments to app onboarding","is_correct":false},{"id":"b","text":"The implementation of event tracking code to capture user actions in the product","is_correct":true},{"id":"c","text":"A hardware testing process","is_correct":false},{"id":"d","text":"The design of analytics dashboards","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'What is the difference between a metric and a KPI?', '[{"id":"a","text":"There is no difference","is_correct":false},{"id":"b","text":"A KPI is a key metric directly tied to strategic business goals, while a metric is any measurable value","is_correct":true},{"id":"c","text":"Metrics are for designers; KPIs are for engineers","is_correct":false},{"id":"d","text":"KPIs are only used in finance","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'A/B testing in analytics requires a control group because:', '[{"id":"a","text":"Legal regulations require it","is_correct":false},{"id":"b","text":"It provides a baseline to measure whether the variant actually caused a change in behavior","is_correct":true},{"id":"c","text":"The control group gets the new feature first","is_correct":false},{"id":"d","text":"It reduces server load","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA201'), 'multiple_choice', 'Feature adoption rate measures:', '[{"id":"a","text":"How fast engineers ship features","is_correct":false},{"id":"b","text":"The percentage of users who use a specific feature at least once within a defined period","is_correct":true},{"id":"c","text":"The number of features launched per quarter","is_correct":false},{"id":"d","text":"How users rate features in surveys","is_correct":false}]', 1, true, true, 2);
