INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'The primary goal of usability testing is to:', '[{"id":"a","text":"Prove the design is correct","is_correct":false},{"id":"b","text":"Identify usability problems by observing real users attempting tasks","is_correct":true},{"id":"c","text":"Measure page load times","is_correct":false},{"id":"d","text":"Get user opinions on visual aesthetics","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'In a moderated usability test, the facilitator:', '[{"id":"a","text":"Completes tasks alongside the participant","is_correct":false},{"id":"b","text":"Guides the session live, can ask follow-up questions, and observes the participant","is_correct":true},{"id":"c","text":"Watches recordings after the session","is_correct":false},{"id":"d","text":"Reads tasks to the participant and scores each one immediately","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'A task scenario in usability testing should be:', '[{"id":"a","text":"Hypothetical and unrelated to real use","is_correct":false},{"id":"b","text":"Realistic, goal-oriented, and not reveal how to complete the task","is_correct":true},{"id":"c","text":"As detailed as possible with step-by-step instructions","is_correct":false},{"id":"d","text":"Written in technical language for accuracy","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'Task completion rate in usability testing measures:', '[{"id":"a","text":"How fast users complete tasks","is_correct":false},{"id":"b","text":"The percentage of users who successfully complete a given task","is_correct":true},{"id":"c","text":"The number of tasks in a test session","is_correct":false},{"id":"d","text":"User satisfaction with a task","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'The SUS (System Usability Scale) is a:', '[{"id":"a","text":"Database query language","is_correct":false},{"id":"b","text":"10-question standardized questionnaire that measures perceived usability","is_correct":true},{"id":"c","text":"Screen recording tool","is_correct":false},{"id":"d","text":"Heuristic evaluation method","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'What is the advantage of remote unmoderated testing?', '[{"id":"a","text":"You can ask follow-up questions during the session","is_correct":false},{"id":"b","text":"It scales to many participants quickly and reduces scheduling overhead","is_correct":true},{"id":"c","text":"It always produces higher quality insights than moderated testing","is_correct":false},{"id":"d","text":"Participants behave more naturally in a lab","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'Why should facilitators avoid helping participants during usability testing?', '[{"id":"a","text":"It wastes time","is_correct":false},{"id":"b","text":"Helping masks genuine usability problems that would surface without assistance","is_correct":true},{"id":"c","text":"Participants prefer to work alone","is_correct":false},{"id":"d","text":"Legal restrictions prevent facilitator involvement","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'An eye-tracking study in usability research tracks:', '[{"id":"a","text":"Mouse cursor movements","is_correct":false},{"id":"b","text":"Where participants look on the screen using specialized hardware or software","is_correct":true},{"id":"c","text":"The speed of eye blinking as a stress indicator","is_correct":false},{"id":"d","text":"Participant attention span","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'The five-second test is used to evaluate:', '[{"id":"a","text":"Page load performance","is_correct":false},{"id":"b","text":"What users immediately notice and understand about a design at first glance","is_correct":true},{"id":"c","text":"How quickly users can complete tasks","is_correct":false},{"id":"d","text":"Navigation label clarity","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'Benchmark testing in usability research is used to:', '[{"id":"a","text":"Compare two different designs with each other","is_correct":false},{"id":"b","text":"Establish performance baselines and measure improvement over time","is_correct":true},{"id":"c","text":"Recruit participants more efficiently","is_correct":false},{"id":"d","text":"Write test scripts automatically","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'How many participants are typically sufficient for a moderated usability test?', '[{"id":"a","text":"100 or more","is_correct":false},{"id":"b","text":"5-8 per user segment","is_correct":true},{"id":"c","text":"Exactly 30","is_correct":false},{"id":"d","text":"1-2","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'Error rate in usability testing measures:', '[{"id":"a","text":"Server errors during the session","is_correct":false},{"id":"b","text":"The frequency of mistakes participants make while attempting tasks","is_correct":true},{"id":"c","text":"Typos in the test script","is_correct":false},{"id":"d","text":"Incorrect question answers","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'What is a cognitive walkthrough in UX evaluation?', '[{"id":"a","text":"A session where users walk through an office","is_correct":false},{"id":"b","text":"An expert evaluation method that simulates how a user would learn and use an interface step by step","is_correct":true},{"id":"c","text":"A usability test conducted while walking","is_correct":false},{"id":"d","text":"A survey about cognitive abilities","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'A RITE (Rapid Iterative Testing and Evaluation) method means:', '[{"id":"a","text":"Testing with a large group all at once","is_correct":false},{"id":"b","text":"Fixing usability problems as they are found between participants rather than waiting until after all sessions","is_correct":true},{"id":"c","text":"Testing in less than 5 minutes per participant","is_correct":false},{"id":"d","text":"Using automated testing tools","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'What is a usability severity rating used for?', '[{"id":"a","text":"Rating participant behavior in a session","is_correct":false},{"id":"b","text":"Prioritizing which usability problems to fix first based on impact and frequency","is_correct":true},{"id":"c","text":"Grading the quality of the test facilitator","is_correct":false},{"id":"d","text":"Measuring the statistical significance of findings","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'Tree testing evaluates:', '[{"id":"a","text":"The performance of navigation animations","is_correct":false},{"id":"b","text":"How findable content is within an information architecture without visual design influence","is_correct":true},{"id":"c","text":"Branching logic in user flows","is_correct":false},{"id":"d","text":"How users navigate a forest-themed app","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'The best way to handle a participant who is silent during a think-aloud session is to:', '[{"id":"a","text":"End the session early","is_correct":false},{"id":"b","text":"Use a neutral prompt such as What are you thinking right now? to encourage verbalization","is_correct":true},{"id":"c","text":"Complete the task for them","is_correct":false},{"id":"d","text":"Tell them what to say","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'What is participant bias in usability testing?', '[{"id":"a","text":"Participants choosing to drop out of the study","is_correct":false},{"id":"b","text":"Participants modifying their behavior because they know they are being observed or want to please the researcher","is_correct":true},{"id":"c","text":"The researcher selecting only positive results","is_correct":false},{"id":"d","text":"Testing with unrepresentative participants","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'A usability test report should prioritize issues by:', '[{"id":"a","text":"The order in which they were discovered","is_correct":false},{"id":"b","text":"Their frequency and impact on user success and satisfaction","is_correct":true},{"id":"c","text":"The researcher''s personal preference","is_correct":false},{"id":"d","text":"Alphabetical order of the feature names","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR201'), 'multiple_choice', 'What makes a good usability test task scenario?', '[{"id":"a","text":"It should mention the UI element the user needs to click","is_correct":false},{"id":"b","text":"It should describe a realistic goal without revealing the solution path","is_correct":true},{"id":"c","text":"It should be as short as possible","is_correct":false},{"id":"d","text":"It should include screenshots of the interface","is_correct":false}]', 1, true, true, 2);
