INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'A micro-interaction is best defined as:', '[{"id":"a","text":"A very small screen size design","is_correct":false},{"id":"b","text":"A contained product moment that accomplishes a single task with a trigger, rule, feedback, and loops or modes","is_correct":true},{"id":"c","text":"An animation that takes less than 1 second","is_correct":false},{"id":"d","text":"A button that fits in a small space","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Affordance in interaction design means:', '[{"id":"a","text":"How much a design costs to build","is_correct":false},{"id":"b","text":"A property of an object that suggests how it should be used","is_correct":true},{"id":"c","text":"The accessibility features of a product","is_correct":false},{"id":"d","text":"The screen area available for interaction","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'A hover state in UI design communicates:', '[{"id":"a","text":"That the element is broken","is_correct":false},{"id":"b","text":"That the element is interactive and responds to the cursor position","is_correct":true},{"id":"c","text":"The loading state of content","is_correct":false},{"id":"d","text":"That a form field has an error","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'The principle of "easing" in UI animation refers to:', '[{"id":"a","text":"Simplifying complex features","is_correct":false},{"id":"b","text":"Varying the acceleration of an animation to feel more natural and physical","is_correct":true},{"id":"c","text":"Reducing the file size of animations","is_correct":false},{"id":"d","text":"Making interactions easier for novice users","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Feedback in interaction design means the system:', '[{"id":"a","text":"Sends emails to users about their behavior","is_correct":false},{"id":"b","text":"Communicates the results of an action to the user to confirm something happened","is_correct":true},{"id":"c","text":"Collects user reviews","is_correct":false},{"id":"d","text":"Returns data to the database","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Empty states in UI design are important because:', '[{"id":"a","text":"They indicate a bug","is_correct":false},{"id":"b","text":"They provide an opportunity to guide users and set expectations when no content is present","is_correct":true},{"id":"c","text":"They save server resources","is_correct":false},{"id":"d","text":"They are required by accessibility standards","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'What is a skeleton screen?', '[{"id":"a","text":"A wireframe with bones-shaped components","is_correct":false},{"id":"b","text":"A loading placeholder that mimics the layout of content while it loads","is_correct":true},{"id":"c","text":"A design for an anatomy education app","is_correct":false},{"id":"d","text":"A dark-mode-only layout","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Gesture-based interactions on touch devices rely on:', '[{"id":"a","text":"Keyboard shortcuts","is_correct":false},{"id":"b","text":"Physical touch inputs such as swipe, pinch, tap, and long press","is_correct":true},{"id":"c","text":"Voice commands","is_correct":false},{"id":"d","text":"Mouse hover events","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Signifiers in interaction design are:', '[{"id":"a","text":"Hidden easter eggs in the UI","is_correct":false},{"id":"b","text":"Perceptible signals that communicate how an interface element should be used","is_correct":true},{"id":"c","text":"Color-coded warning signs","is_correct":false},{"id":"d","text":"Legal disclaimers in the UI","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'What is the primary purpose of a loading animation?', '[{"id":"a","text":"To fill time while the developer optimizes backend queries","is_correct":false},{"id":"b","text":"To communicate that the system is working and reduce perceived wait time","is_correct":true},{"id":"c","text":"To entertain users","is_correct":false},{"id":"d","text":"To display brand colors","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Optimistic UI is a pattern where:', '[{"id":"a","text":"The interface always shows positive messages","is_correct":false},{"id":"b","text":"The UI assumes an action will succeed and updates immediately without waiting for server confirmation","is_correct":true},{"id":"c","text":"The app only works when online","is_correct":false},{"id":"d","text":"Animations are always positive and uplifting","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'What are the four components of a micro-interaction?', '[{"id":"a","text":"Color, Size, Shape, Motion","is_correct":false},{"id":"b","text":"Trigger, Rules, Feedback, Loops and Modes","is_correct":true},{"id":"c","text":"Input, Output, State, Logic","is_correct":false},{"id":"d","text":"Action, Reaction, Result, Confirmation","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Destructive actions (like delete) should always:', '[{"id":"a","text":"Happen immediately for speed","is_correct":false},{"id":"b","text":"Require confirmation or provide an undo option to prevent accidental data loss","is_correct":true},{"id":"c","text":"Be hidden from users","is_correct":false},{"id":"d","text":"Be coded in red only","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'What is the purpose of a transition animation between screens?', '[{"id":"a","text":"To slow down the product and give the server more time","is_correct":false},{"id":"b","text":"To communicate spatial relationships and maintain context as the user navigates","is_correct":true},{"id":"c","text":"To impress stakeholders during demos","is_correct":false},{"id":"d","text":"To comply with animation libraries","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'When should animation be avoided in a UI?', '[{"id":"a","text":"When the user is using a dark theme","is_correct":false},{"id":"b","text":"When users have enabled reduced motion preferences or when animation adds no functional value","is_correct":true},{"id":"c","text":"When the app has fewer than 100 users","is_correct":false},{"id":"d","text":"When CSS is not available","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'The principle of direct manipulation means:', '[{"id":"a","text":"The developer directly edits the code","is_correct":false},{"id":"b","text":"Users interact with visual representations of objects rather than using indirect command syntax","is_correct":true},{"id":"c","text":"Admins can directly change user data","is_correct":false},{"id":"d","text":"Designers manipulate pixels directly","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Haptic feedback in mobile design is used to:', '[{"id":"a","text":"Display visual notifications","is_correct":false},{"id":"b","text":"Provide tactile confirmation of user actions through vibration","is_correct":true},{"id":"c","text":"Improve audio quality","is_correct":false},{"id":"d","text":"Detect user location","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'What is an interaction pattern?', '[{"id":"a","text":"A bug that appears in a repeating sequence","is_correct":false},{"id":"b","text":"A reusable solution to a common interaction design problem","is_correct":true},{"id":"c","text":"A color scheme applied to multiple screens","is_correct":false},{"id":"d","text":"A user behavior tracked by analytics","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'Voice user interfaces (VUIs) present unique design challenges because:', '[{"id":"a","text":"They require more colors","is_correct":false},{"id":"b","text":"Users cannot see available options, requiring careful design of discoverability and error handling","is_correct":true},{"id":"c","text":"They work only on iOS","is_correct":false},{"id":"d","text":"Voice input is slower than touch","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES202'), 'multiple_choice', 'The "principle of least surprise" in interaction design states that:', '[{"id":"a","text":"Interfaces should always surprise users to keep them engaged","is_correct":false},{"id":"b","text":"A system should behave consistently with user expectations to reduce errors and confusion","is_correct":true},{"id":"c","text":"Error messages should be hidden to avoid alarming users","is_correct":false},{"id":"d","text":"New features should be announced with surprises","is_correct":false}]', 1, true, true, 3);
