INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'In React, what is JSX?', '[{"id":"a","text":"A JavaScript testing framework","is_correct":false},{"id":"b","text":"A syntax extension that allows writing HTML-like code in JavaScript","is_correct":true},{"id":"c","text":"A JSON variant used by React","is_correct":false},{"id":"d","text":"A CSS preprocessor","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'Props in React are:', '[{"id":"a","text":"Internal state variables of a component","is_correct":false},{"id":"b","text":"Read-only data passed from a parent component to a child component","is_correct":true},{"id":"c","text":"CSS properties applied to components","is_correct":false},{"id":"d","text":"Database properties accessed by components","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'What does the useState hook return?', '[{"id":"a","text":"A single state value","is_correct":false},{"id":"b","text":"An array containing the current state value and a function to update it","is_correct":true},{"id":"c","text":"A Promise resolving to the state","is_correct":false},{"id":"d","text":"The previous and current state values","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'The useEffect hook is primarily used for:', '[{"id":"a","text":"Applying CSS styles to components","is_correct":false},{"id":"b","text":"Performing side effects such as data fetching, subscriptions, and DOM manipulation","is_correct":true},{"id":"c","text":"Creating context providers","is_correct":false},{"id":"d","text":"Memoizing expensive calculations","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'What is the virtual DOM in React?', '[{"id":"a","text":"An external database for React applications","is_correct":false},{"id":"b","text":"A lightweight in-memory representation of the real DOM used to minimize actual DOM updates","is_correct":true},{"id":"c","text":"A CSS-in-JS solution","is_correct":false},{"id":"d","text":"A testing environment that simulates the browser","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'In React, keys in lists are used to:', '[{"id":"a","text":"Style list items uniquely","is_correct":false},{"id":"b","text":"Help React identify which items have changed, been added, or removed for efficient rendering","is_correct":true},{"id":"c","text":"Sort list items automatically","is_correct":false},{"id":"d","text":"Prevent duplicate values","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'What is lifting state up in React?', '[{"id":"a","text":"Moving state from local storage to the server","is_correct":false},{"id":"b","text":"Moving shared state to a common ancestor component so multiple children can access it","is_correct":true},{"id":"c","text":"Using Redux for global state management","is_correct":false},{"id":"d","text":"Promoting a component to a higher-order component","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'The React Context API is used to:', '[{"id":"a","text":"Connect React to a database","is_correct":false},{"id":"b","text":"Share data across a component tree without passing props down manually at every level","is_correct":true},{"id":"c","text":"Handle routing between pages","is_correct":false},{"id":"d","text":"Apply global CSS styles","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'In React, a controlled component is one where:', '[{"id":"a","text":"The component controls other components","is_correct":false},{"id":"b","text":"Form data is handled by React state rather than the DOM","is_correct":true},{"id":"c","text":"The component has no children","is_correct":false},{"id":"d","text":"The component is wrapped in a HOC","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'What is a custom hook in React?', '[{"id":"a","text":"A hook that modifies existing React hooks","is_correct":false},{"id":"b","text":"A JavaScript function starting with use that encapsulates reusable stateful logic","is_correct":true},{"id":"c","text":"A hook provided by a third-party library only","is_correct":false},{"id":"d","text":"A hook that only works with class components","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'React.memo is used to:', '[{"id":"a","text":"Store data in browser memory","is_correct":false},{"id":"b","text":"Prevent unnecessary re-renders of a component when props have not changed","is_correct":true},{"id":"c","text":"Create memoized selectors in Redux","is_correct":false},{"id":"d","text":"Cache API responses in React","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'When should you use useCallback?', '[{"id":"a","text":"When you want to cache the result of an expensive computation","is_correct":false},{"id":"b","text":"When you want to memoize a function so it is not recreated on every render","is_correct":true},{"id":"c","text":"When you need to call a function asynchronously","is_correct":false},{"id":"d","text":"When you are fetching data from an API","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'What is the purpose of the dependency array in useEffect?', '[{"id":"a","text":"It lists the props available in the component","is_correct":false},{"id":"b","text":"It controls when the effect runs by specifying which values trigger a re-run when they change","is_correct":true},{"id":"c","text":"It defines which components depend on this one","is_correct":false},{"id":"d","text":"It lists external libraries used in the effect","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'Reconciliation in React refers to:', '[{"id":"a","text":"Resolving conflicts between team members","is_correct":false},{"id":"b","text":"The algorithm React uses to diff the virtual DOM and determine the minimum set of DOM updates needed","is_correct":true},{"id":"c","text":"Combining multiple components into one","is_correct":false},{"id":"d","text":"Syncing local state with the server","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'Error boundaries in React are used to:', '[{"id":"a","text":"Validate user input in forms","is_correct":false},{"id":"b","text":"Catch JavaScript errors in a component tree and display a fallback UI instead of crashing","is_correct":true},{"id":"c","text":"Handle HTTP errors from API calls","is_correct":false},{"id":"d","text":"Prevent CSS styling errors","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'What is code splitting in React?', '[{"id":"a","text":"Dividing the codebase between frontend and backend developers","is_correct":false},{"id":"b","text":"Splitting the bundle into smaller chunks loaded on demand to improve initial load performance","is_correct":true},{"id":"c","text":"Separating CSS from JavaScript files","is_correct":false},{"id":"d","text":"Splitting a large component into multiple functions","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'The useMemo hook is used for:', '[{"id":"a","text":"Memorizing user data","is_correct":false},{"id":"b","text":"Caching the result of an expensive calculation and only recomputing when dependencies change","is_correct":true},{"id":"c","text":"Storing the previous state value","is_correct":false},{"id":"d","text":"Accessing DOM elements directly","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'What is prop drilling in React?', '[{"id":"a","text":"Passing props down multiple levels of the component tree just to reach a deeply nested component","is_correct":true},{"id":"b","text":"Passing too many props to a single component","is_correct":false},{"id":"c","text":"Drilling into DOM elements with refs","is_correct":false},{"id":"d","text":"Passing functions as props","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'React Suspense is used for:', '[{"id":"a","text":"Adding loading spinners to all components","is_correct":false},{"id":"b","text":"Declaratively specifying a loading state while waiting for lazy-loaded components or async data","is_correct":true},{"id":"c","text":"Pausing animations","is_correct":false},{"id":"d","text":"Delaying API calls","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV202'), 'multiple_choice', 'In React, what does the children prop represent?', '[{"id":"a","text":"Child components created by a component","is_correct":false},{"id":"b","text":"The content passed between a component''s opening and closing tags","is_correct":true},{"id":"c","text":"Child routes in React Router","is_correct":false},{"id":"d","text":"Nested state variables","is_correct":false}]', 1, true, true, 2);
