INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What is the primary purpose of a product roadmap?', '[{"id":"a","text":"A step-by-step plan for developers to follow","is_correct":false},{"id":"b","text":"A strategic communication tool that shows the direction, priorities, and planned outcomes for a product over time","is_correct":true},{"id":"c","text":"A list of all bugs to fix","is_correct":false},{"id":"d","text":"A project schedule with exact delivery dates","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'An outcome-based roadmap differs from a feature-based roadmap because:', '[{"id":"a","text":"It uses Gantt charts","is_correct":false},{"id":"b","text":"It organizes work around user and business outcomes rather than specific features","is_correct":true},{"id":"c","text":"It is only used by startups","is_correct":false},{"id":"d","text":"It does not include timelines","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'The Now/Next/Later roadmap format is useful because:', '[{"id":"a","text":"It hides future plans from competitors","is_correct":false},{"id":"b","text":"It communicates priorities at different time horizons with appropriate levels of confidence","is_correct":true},{"id":"c","text":"It includes exact delivery dates for all items","is_correct":false},{"id":"d","text":"It replaces the product backlog","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What is a theme-based roadmap?', '[{"id":"a","text":"A roadmap using different colors for different teams","is_correct":false},{"id":"b","text":"A roadmap organized around strategic themes or problem areas rather than specific features","is_correct":true},{"id":"c","text":"A roadmap created for a specific industry vertical","is_correct":false},{"id":"d","text":"A roadmap with design themes","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'Why are fixed-date roadmaps often problematic in agile teams?', '[{"id":"a","text":"They are too long to create","is_correct":false},{"id":"b","text":"They create pressure to ship incomplete work and reduce flexibility to respond to learning","is_correct":true},{"id":"c","text":"They cannot be shared with stakeholders","is_correct":false},{"id":"d","text":"They require too many tools","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'OKRs (Objectives and Key Results) are used on a roadmap to:', '[{"id":"a","text":"Replace the product backlog","is_correct":false},{"id":"b","text":"Connect roadmap items to measurable outcomes and strategic goals","is_correct":true},{"id":"c","text":"Track individual performance","is_correct":false},{"id":"d","text":"Define technical architecture","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'When presenting a roadmap to executives, which format is most effective?', '[{"id":"a","text":"A detailed spreadsheet with story point estimates","is_correct":false},{"id":"b","text":"A high-level strategic view focused on outcomes, impact, and alignment to business goals","is_correct":true},{"id":"c","text":"A technical architecture diagram","is_correct":false},{"id":"d","text":"A sprint-by-sprint breakdown","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'How often should a product roadmap be updated?', '[{"id":"a","text":"Once a year during annual planning","is_correct":false},{"id":"b","text":"Regularly — at least quarterly or whenever significant new information or learnings emerge","is_correct":true},{"id":"c","text":"Only when a major feature ships","is_correct":false},{"id":"d","text":"Never — a roadmap is a commitment once set","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What is a public roadmap?', '[{"id":"a","text":"A roadmap printed and posted on the office wall","is_correct":false},{"id":"b","text":"A roadmap shared externally with customers and the public to communicate product direction","is_correct":true},{"id":"c","text":"A roadmap accessible to all internal employees","is_correct":false},{"id":"d","text":"A roadmap created without stakeholder input","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What is the difference between a roadmap and a product backlog?', '[{"id":"a","text":"They are the same document","is_correct":false},{"id":"b","text":"The roadmap shows strategic direction and themes; the backlog contains the detailed prioritized list of work items","is_correct":true},{"id":"c","text":"The backlog is for engineering; the roadmap is for marketing","is_correct":false},{"id":"d","text":"The backlog is always longer than the roadmap","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'Horizon planning in roadmapping refers to:', '[{"id":"a","text":"Planning for sunset and end-of-life features","is_correct":false},{"id":"b","text":"Organizing work into time-based categories with different levels of confidence and detail","is_correct":true},{"id":"c","text":"Planning launches for sunrise events","is_correct":false},{"id":"d","text":"Strategic planning for 10+ years","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What is a roadmap anti-pattern known as "the graveyard"?', '[{"id":"a","text":"A section for deprecated features","is_correct":false},{"id":"b","text":"A long-term backlog of items that never get prioritized or removed, creating false expectations","is_correct":true},{"id":"c","text":"A roadmap section for emergency fixes","is_correct":false},{"id":"d","text":"A private roadmap not shared with anyone","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'Opportunity scoring on a roadmap helps teams:', '[{"id":"a","text":"Score product designers on performance","is_correct":false},{"id":"b","text":"Quantify the potential value and feasibility of items to support prioritization decisions","is_correct":true},{"id":"c","text":"Calculate development cost estimates","is_correct":false},{"id":"d","text","is_correct":false},{"id":"d","text":"Track how many opportunities were missed","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'Why should a roadmap include "why" for each initiative?', '[{"id":"a","text":"To add length to the document","is_correct":false},{"id":"b","text":"To provide context so teams understand the problem they are solving and can make better decisions","is_correct":true},{"id":"c","text":"Because legal requires a rationale","is_correct":false},{"id":"d","text":"To satisfy investor relations requirements","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'A continuous discovery roadmap is one that:', '[{"id":"a","text":"Is updated every day","is_correct":false},{"id":"b","text":"Incorporates learnings from ongoing user research to continuously adjust priorities and direction","is_correct":true},{"id":"c","text":"Has no fixed items","is_correct":false},{"id":"d","text":"Uses only quantitative data","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What does "dual-track agile" mean in the context of roadmapping?', '[{"id":"a","text":"Having two separate product teams","is_correct":false},{"id":"b","text":"Running discovery and delivery in parallel tracks so learning and building happen simultaneously","is_correct":true},{"id":"c","text":"Splitting the roadmap into two versions","is_correct":false},{"id":"d","text":"Using two different agile methodologies at once","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What should a product manager do when a stakeholder insists on adding an unplanned item to the roadmap?', '[{"id":"a","text":"Add it immediately to avoid conflict","is_correct":false},{"id":"b","text":"Evaluate the request against strategic goals and current priorities and discuss trade-offs transparently","is_correct":true},{"id":"c","text":"Reject it without discussion","is_correct":false},{"id":"d","text":"Add it to the backlog without communicating when it will be done","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'What is the risk of committing to exact dates on a roadmap?', '[{"id":"a","text":"Stakeholders prefer estimates","is_correct":false},{"id":"b","text":"Teams may sacrifice quality or discovery to meet deadlines, and surprises destroy trust","is_correct":true},{"id":"c","text":"It increases engineering velocity","is_correct":false},{"id":"d","text":"Customers dislike specificity","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'Impact mapping in roadmapping is a technique for:', '[{"id":"a","text":"Mapping customer locations","is_correct":false},{"id":"b","text":"Connecting goals to actors, impacts, and deliverables to ensure roadmap items are tied to real outcomes","is_correct":true},{"id":"c","text":"Calculating the environmental impact of software","is_correct":false},{"id":"d","text":"Prioritizing UI design tasks","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM202'), 'multiple_choice', 'When roadmaps conflict between teams, the right resolution approach is:', '[{"id":"a","text":"The most senior person wins","is_correct":false},{"id":"b","text":"Align on shared strategy and prioritize based on company-level goals and customer impact","is_correct":true},{"id":"c","text":"Combine all roadmaps into one massive document","is_correct":false},{"id":"d","text":"Ignore the conflict and proceed independently","is_correct":false}]', 1, true, true, 3);
