INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'A heatmap in web analytics shows:', '[{"id":"a","text":"The geographic distribution of users","is_correct":false},{"id":"b","text":"Where users click, move, or scroll on a page using color intensity","is_correct":true},{"id":"c","text":"Server temperature during peak traffic","is_correct":false},{"id":"d","text":"The color preferences of users","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'What does a scroll map reveal?', '[{"id":"a","text":"How fast users scroll through content","is_correct":false},{"id":"b","text":"How far down the page users scroll before leaving","is_correct":true},{"id":"c","text":"The number of scroll events per session","is_correct":false},{"id":"d","text":"The scroll speed of the page","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Statistical significance in A/B testing means:', '[{"id":"a","text":"The sample size is very large","is_correct":false},{"id":"b","text":"The observed difference is unlikely to have occurred by chance and can be attributed to the design change","is_correct":true},{"id":"c","text":"The test has been running for a statistically determined time","is_correct":false},{"id":"d","text":"Both variants perform the same","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Session recordings in analytics tools allow teams to:', '[{"id":"a","text":"Record audio during user sessions","is_correct":false},{"id":"b","text":"Watch replays of real user sessions to understand behavior and spot friction","is_correct":true},{"id":"c","text":"Record team meetings about design decisions","is_correct":false},{"id":"d","text":"Replay server logs visually","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Why should design decisions not rely solely on quantitative data?', '[{"id":"a","text":"Numbers are always wrong","is_correct":false},{"id":"b","text":"Quantitative data shows what is happening but rarely explains why, requiring qualitative insight","is_correct":true},{"id":"c","text":"Quantitative data is too expensive","is_correct":false},{"id":"d","text":"Most analytics tools have inaccurate data","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Conversion rate optimization (CRO) aims to:', '[{"id":"a","text":"Convert legacy code to modern JavaScript","is_correct":false},{"id":"b","text":"Increase the percentage of users who complete a desired action","is_correct":true},{"id":"c","text":"Optimize database queries","is_correct":false},{"id":"d","text":"Convert free users to paid users only","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'What is a multivariate test?', '[{"id":"a","text":"A test with multiple participants","is_correct":false},{"id":"b","text":"A test that evaluates multiple variables or combinations simultaneously to find the best-performing version","is_correct":true},{"id":"c","text":"An A/B test with more than two variants","is_correct":false},{"id":"d","text":"A test that runs in multiple countries","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Segmenting analytics data by user type helps designers:', '[{"id":"a","text":"Reduce the dataset to manageable size","is_correct":false},{"id":"b","text":"Understand how different user groups interact with the product to identify targeted design improvements","is_correct":true},{"id":"c","text":"Comply with GDPR requirements","is_correct":false},{"id":"d","text":"Reduce server costs","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Dead clicks in a heatmap indicate:', '[{"id":"a","text":"Broken links on the page","is_correct":false},{"id":"b","text":"Areas where users click but nothing happens, suggesting confusion about interactivity","is_correct":true},{"id":"c","text":"Clicks that did not register in the database","is_correct":false},{"id":"d","text":"Buttons that have been disabled","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Time on task as a usability metric measures:', '[{"id":"a","text":"Total session duration","is_correct":false},{"id":"b","text":"How long it takes a user to complete a specific task","is_correct":true},{"id":"c","text":"The time a user spends reading content","is_correct":false},{"id":"d","text":"How long until the page fully loads","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'What is a p-value in the context of design experimentation?', '[{"id":"a","text":"A performance score for page load speed","is_correct":false},{"id":"b","text":"The probability that the observed results occurred by chance — lower values indicate stronger evidence against the null hypothesis","is_correct":true},{"id":"c","text":"A priority value assigned to design tasks","is_correct":false},{"id":"d","text":"A personalization variable in the analytics dashboard","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'What is the danger of running too many A/B tests simultaneously?', '[{"id":"a","text":"It slows down the server","is_correct":false},{"id":"b","text":"Tests can interfere with each other producing unreliable results due to interaction effects","is_correct":true},{"id":"c","text":"Users get confused by multiple versions","is_correct":false},{"id":"d","text":"Engineering teams spend too much time reviewing results","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'What is qualitative data enrichment in the context of analytics?', '[{"id":"a","text":"Cleaning typos from user-submitted text","is_correct":false},{"id":"b","text":"Adding qualitative context (interviews, open-ended survey responses) to explain quantitative patterns","is_correct":true},{"id":"c","text":"Converting qualitative data to numbers","is_correct":false},{"id":"d","text":"Enriching user profiles with demographic data","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Which of the following is an example of a leading metric for engagement?', '[{"id":"a","text":"Monthly recurring revenue","is_correct":false},{"id":"b","text":"Number of core actions performed per user per week","is_correct":true},{"id":"c","text":"Annual churn rate","is_correct":false},{"id":"d","text":"Customer lifetime value","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'The HEART framework (Google) stands for:', '[{"id":"a","text":"Happiness, Engagement, Adoption, Retention, Task Success","is_correct":true},{"id":"b","text":"Heatmaps, Events, Analytics, Retention, Testing","is_correct":false},{"id":"c","text":"Hierarchy, Engagement, Activation, Revenue, Traffic","is_correct":false},{"id":"d","text":"Happiness, Efficiency, Automation, Reach, Testing","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'What is a novelty effect in A/B testing?', '[{"id":"a","text":"Users prefer the newer version because of its new features","is_correct":false},{"id":"b","text":"Users interact more with the variant simply because it is new, temporarily skewing results","is_correct":true},{"id":"c","text":"The test produces novel statistical results","is_correct":false},{"id":"d","text":"A variant that introduces novel UI patterns","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Which metric would best indicate that a redesigned onboarding flow is successful?', '[{"id":"a","text":"Page views of the onboarding screens","is_correct":false},{"id":"b","text":"Increase in the percentage of users who complete onboarding and reach the aha moment","is_correct":true},{"id":"c","text":"Number of support tickets about onboarding","is_correct":false},{"id":"d","text":"Time spent on the onboarding screens","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Data sampling in analytics means:', '[{"id":"a","text":"Testing designs with a sample of users","is_correct":false},{"id":"b","text":"Analyzing a subset of data rather than the full dataset when volumes are too large","is_correct":true},{"id":"c","text":"Collecting samples of user feedback","is_correct":false},{"id":"d","text":"A method of randomly assigning users to A/B variants","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'What is the aha moment in product analytics?', '[{"id":"a","text":"The moment a user encounters a bug","is_correct":false},{"id":"b","text":"The specific moment when a user first experiences the core value of the product","is_correct":true},{"id":"c","text":"When an A/B test reaches significance","is_correct":false},{"id":"d","text":"A surprise feature discovery","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA202'), 'multiple_choice', 'Why is it important to define success metrics before running an experiment?', '[{"id":"a","text":"To save time by avoiding data collection","is_correct":false},{"id":"b","text":"To prevent HARKing (Hypothesizing After Results are Known) and ensure objective evaluation","is_correct":true},{"id":"c","text":"Because analytics tools require pre-defined metrics","is_correct":false},{"id":"d","text":"To satisfy regulatory requirements","is_correct":false}]', 1, true, true, 3);
