INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'A user journey map is primarily used to:', '[{"id":"a","text":"Document the technical flow of an application","is_correct":false},{"id":"b","text":"Visualize the end-to-end experience of a user interacting with a product or service","is_correct":true},{"id":"c","text":"Plan marketing campaigns","is_correct":false},{"id":"d","text":"Map database relationships","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'Which component of a journey map captures the user''s emotional state?', '[{"id":"a","text":"Touchpoints","is_correct":false},{"id":"b","text":"Channels","is_correct":false},{"id":"c","text":"Emotional curve or sentiment lane","is_correct":true},{"id":"d","text":"Pain points","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'A touchpoint in a journey map is:', '[{"id":"a","text":"A physical location where users meet the product team","is_correct":false},{"id":"b","text":"Any point where the user interacts with the product or service","is_correct":true},{"id":"c","text":"A critical bug that disrupts the user flow","is_correct":false},{"id":"d","text":"A technical integration endpoint","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'A service blueprint differs from a journey map in that it:', '[{"id":"a","text":"Is used by marketing teams only","is_correct":false},{"id":"b","text":"Also includes backstage processes, support systems, and internal team actions not visible to the user","is_correct":true},{"id":"c","text":"Does not include user emotions","is_correct":false},{"id":"d","text":"Focuses only on the digital experience","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'The stages in a typical B2C e-commerce journey map include:', '[{"id":"a","text":"Plan, Build, Ship, Support","is_correct":false},{"id":"b","text":"Awareness, Consideration, Purchase, Post-purchase, Loyalty","is_correct":true},{"id":"c","text":"Design, Develop, Test, Deploy","is_correct":false},{"id":"d","text":"Onboard, Activate, Expand, Renew","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'A current-state journey map shows:', '[{"id":"a","text":"The ideal future experience","is_correct":false},{"id":"b","text":"The existing user experience as it actually is today","is_correct":true},{"id":"c","text":"A competitive analysis of journey maps","is_correct":false},{"id":"d","text":"The internal team''s perspective of the experience","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'A future-state journey map is used to:', '[{"id":"a","text":"Document the current experience","is_correct":false},{"id":"b","text":"Envision and align teams around the desired user experience to design toward","is_correct":true},{"id":"c","text":"Record what users wish the experience was like","is_correct":false},{"id":"d","text":"Plan future user research studies","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'What data should ideally inform a journey map?', '[{"id":"a","text":"Designer assumptions only","is_correct":false},{"id":"b","text":"Real user research including interviews, analytics, and observations","is_correct":true},{"id":"c","text":"Stakeholder opinions","is_correct":false},{"id":"d","text":"Competitor journey maps","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'The moment of truth in a journey map refers to:', '[{"id":"a","text":"When users realize the product is free","is_correct":false},{"id":"b","text":"A critical interaction that significantly impacts the user''s perception and decision to continue or leave","is_correct":true},{"id":"c","text":"When the product is launched","is_correct":false},{"id":"d","text":"The first touchpoint in the journey","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'Pain points in a journey map represent:', '[{"id":"a","text":"Server errors experienced by users","is_correct":false},{"id":"b","text":"Areas where users experience frustration, confusion, or unmet needs","is_correct":true},{"id":"c","text":"Features the competitor has that your product lacks","is_correct":false},{"id":"d","text":"Physical discomfort from using the device","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'What is an opportunity in a journey map?', '[{"id":"a","text":"A new market segment to target","is_correct":false},{"id":"b","text":"A potential improvement that would address a pain point or delight users at a specific stage","is_correct":true},{"id":"c","text":"A feature request from stakeholders","is_correct":false},{"id":"d","text":"A gap in competitor offerings","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'What is the primary risk of creating a journey map without user research?', '[{"id":"a","text":"The map will be too detailed","is_correct":false},{"id":"b","text":"The map will reflect team assumptions rather than real user experiences, leading to poor decisions","is_correct":true},{"id":"c","text":"Stakeholders will not understand it","is_correct":false},{"id":"d","text":"It will take too long to create","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'Which of the following is the line of visibility in a service blueprint?', '[{"id":"a","text":"The emotional curve of the customer","is_correct":false},{"id":"b","text":"The boundary that separates what the customer sees from backstage processes they do not see","is_correct":true},{"id":"c","text":"The line separating digital and physical channels","is_correct":false},{"id":"d","text":"A dotted line showing optional touchpoints","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'How should a journey map be used in a cross-functional team?', '[{"id":"a","text":"It should only be shown to the design team","is_correct":false},{"id":"b","text":"As a shared artifact that creates alignment and empathy across design, product, engineering, and business teams","is_correct":true},{"id":"c","text":"As a replacement for user research","is_correct":false},{"id":"d","text":"As a legal document defining user expectations","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'What does the channel lane in a journey map capture?', '[{"id":"a","text":"The revenue generated per channel","is_correct":false},{"id":"b","text":"The different mediums through which users interact with the product such as app, web, or email","is_correct":true},{"id":"c","text":"The color scheme used across different platforms","is_correct":false},{"id":"d","text":"Marketing attribution data","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'A jobs-to-be-done lens applied to journey mapping helps teams:', '[{"id":"a","text":"Assign tasks to team members","is_correct":false},{"id":"b","text":"Understand the underlying goals and motivations driving user behavior at each stage","is_correct":true},{"id":"c","text":"Create project plans","is_correct":false},{"id":"d","text":"Map database schemas","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'What should teams do after completing a journey map workshop?', '[{"id":"a","text":"File the map away and move on","is_correct":false},{"id":"b","text":"Identify prioritized opportunities, assign owners, and integrate insights into the product roadmap","is_correct":true},{"id":"c","text":"Share it publicly on social media","is_correct":false},{"id":"d","text":"Conduct another journey map workshop immediately","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'What is a proto-journey map?', '[{"id":"a","text":"A journey map created with Figma''s proto feature","is_correct":false},{"id":"b","text":"A hypothesis-based journey map created before research to identify assumptions to validate","is_correct":true},{"id":"c","text":"A simplified journey map for quick sharing","is_correct":false},{"id":"d","text":"A prototype that contains journey mapping features","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'The emotional curve in a journey map typically uses:', '[{"id":"a","text":"A color-coded bar chart","is_correct":false},{"id":"b","text":"A line graph showing highs and lows in user sentiment across journey stages","is_correct":true},{"id":"c","text":"A pie chart of positive vs negative feelings","is_correct":false},{"id":"d","text":"A histogram of support tickets","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'UXR202'), 'multiple_choice', 'When is a service blueprint preferred over a customer journey map?', '[{"id":"a","text":"When the team only wants to focus on digital channels","is_correct":false},{"id":"b","text":"When the goal is to understand and improve both the customer experience and the internal operational processes that support it","is_correct":true},{"id":"c","text":"When the product has fewer than 5 touchpoints","is_correct":false},{"id":"d","text":"When the team has limited research data","is_correct":false}]', 1, true, true, 3);
