INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is rate limiting in an API?', '[{"id":"a","text":"Setting a maximum response payload size","is_correct":false},{"id":"b","text":"Restricting how many requests a client can make in a given time period to prevent abuse","is_correct":true},{"id":"c","text":"Limiting the number of database queries per session","is_correct":false},{"id":"d","text":"A cap on server memory usage","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'In REST API design, idempotent means:', '[{"id":"a","text":"The request always succeeds","is_correct":false},{"id":"b","text":"Making the same request multiple times produces the same result as making it once","is_correct":true},{"id":"c","text":"The API does not require authentication","is_correct":false},{"id":"d","text":"The response is always cached","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What does npm stand for?', '[{"id":"a","text":"New Package Manager","is_correct":false},{"id":"b","text":"Node Package Manager","is_correct":true},{"id":"c","text":"Next Program Module","is_correct":false},{"id":"d","text":"Network Protocol Module","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'Which HTTP method is used to partially update a resource?', '[{"id":"a","text":"PUT","is_correct":false},{"id":"b","text":"POST","is_correct":false},{"id":"c","text":"PATCH","is_correct":true},{"id":"d","text":"UPDATE","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is the purpose of an API gateway?', '[{"id":"a","text":"A physical server connecting APIs","is_correct":false},{"id":"b","text":"A server that acts as an entry point for clients, routing requests to backend services and handling cross-cutting concerns","is_correct":true},{"id":"c","text":"A database connection pool","is_correct":false},{"id":"d","text":"A CDN for API responses","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'N+1 query problem in backend development refers to:', '[{"id":"a","text":"Running N plus 1 API endpoints","is_correct":false},{"id":"b","text":"Executing 1 query to get a list then N additional queries for each item, creating performance issues","is_correct":true},{"id":"c","text":"Having N+1 database tables","is_correct":false},{"id":"d","text":"Pagination starting from index 1","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is the benefit of using connection pooling for databases?', '[{"id":"a","text":"It creates a new database connection for every request","is_correct":false},{"id":"b","text":"It reuses a pool of open connections reducing the overhead of creating connections on every request","is_correct":true},{"id":"c","text":"It encrypts all database queries","is_correct":false},{"id":"d","text":"It caches all query results","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is the role of a .env file in Node.js projects?', '[{"id":"a","text":"It contains environment-specific configuration values not committed to source control","is_correct":true},{"id":"b","text":"It stores event handlers","is_correct":false},{"id":"c","text":"It defines npm scripts","is_correct":false},{"id":"d","text":"It contains CSS environment variables","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is the difference between authentication and authorization?', '[{"id":"a","text":"They are the same thing","is_correct":false},{"id":"b","text":"Authentication verifies who you are; authorization determines what you are allowed to do","is_correct":true},{"id":"c","text":"Authentication is for APIs; authorization is for UIs","is_correct":false},{"id":"d","text":"Authentication uses passwords; authorization uses biometrics","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'In Node.js, what is the purpose of the package-lock.json file?', '[{"id":"a","text":"To lock the Node.js version","is_correct":false},{"id":"b","text":"To record the exact versions of all installed dependencies ensuring reproducible installs","is_correct":true},{"id":"c","text":"To prevent new packages from being added","is_correct":false},{"id":"d","text":"To lock the project for read-only access","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is GraphQL and how does it differ from REST?', '[{"id":"a","text":"GraphQL is a graph database; REST is an API style","is_correct":false},{"id":"b","text":"GraphQL allows clients to request exactly the data they need in a single query; REST has fixed endpoints returning fixed data shapes","is_correct":true},{"id":"c","text":"GraphQL is faster; REST is more secure","is_correct":false},{"id":"d","text":"GraphQL uses GET only; REST uses all HTTP methods","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is a webhook?', '[{"id":"a","text":"A hook placed in the frontend that calls backend functions","is_correct":false},{"id":"b","text":"An HTTP callback that allows one server to notify another when a specific event occurs","is_correct":true},{"id":"c","text":"A security hook that validates all requests","is_correct":false},{"id":"d","text":"A built-in Express.js plugin","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'What is the benefit of using async/await in Node.js backend code?', '[{"id":"a","text":"It makes the code run in parallel automatically","is_correct":false},{"id":"b","text":"It allows writing asynchronous code in a synchronous style making it more readable and maintainable","is_correct":true},{"id":"c","text":"It disables the event loop","is_correct":false},{"id":"d","text":"It caches all async operations","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DEV301'), 'multiple_choice', 'A serverless function differs from a traditional server because:', '[{"id":"a","text":"It runs without any code","is_correct":false},{"id":"b","text":"It executes on demand without requiring a persistently running server, scaling automatically","is_correct":true},{"id":"c","text":"It cannot connect to databases","is_correct":false},{"id":"d","text":"It only works with JavaScript","is_correct":false}]', 1, true, true, 3);
