INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'A primary key in a relational database:', '[{"id":"a","text":"Can contain duplicate values","is_correct":false},{"id":"b","text":"Uniquely identifies each row in a table","is_correct":true},{"id":"c","text":"References a key in another table","is_correct":false},{"id":"d","text":"Stores the most important column value","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'A foreign key in a relational database:', '[{"id":"a","text":"Is used to encrypt sensitive data","is_correct":false},{"id":"b","text":"References the primary key of another table to establish a relationship","is_correct":true},{"id":"c","text":"Must be unique across all tables","is_correct":false},{"id":"d","text":"Is generated automatically by the database","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What does the SQL SELECT statement do?', '[{"id":"a","text":"Selects a database to use","is_correct":false},{"id":"b","text":"Retrieves data from one or more tables","is_correct":true},{"id":"c","text":"Creates a new table","is_correct":false},{"id":"d","text":"Deletes selected rows","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is a JOIN in SQL?', '[{"id":"a","text":"A command to combine two databases","is_correct":false},{"id":"b","text":"A clause that combines rows from two or more tables based on a related column","is_correct":true},{"id":"c","text":"A way to merge two columns in a table","is_correct":false},{"id":"d","text","is_correct":false},{"id":"d","text":"A function to concatenate strings","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'First Normal Form (1NF) requires that:', '[{"id":"a","text":"All columns depend on the primary key","is_correct":false},{"id":"b","text":"Each column contains atomic indivisible values and each row is unique","is_correct":true},{"id":"c","text":"There are no duplicate rows","is_correct":false},{"id":"d","text":"The table has no foreign keys","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What does GROUP BY do in SQL?', '[{"id":"a","text":"Sorts the results alphabetically","is_correct":false},{"id":"b","text":"Groups rows that have the same values in specified columns to apply aggregate functions","is_correct":true},{"id":"c","text":"Merges two tables together","is_correct":false},{"id":"d","text":"Filters rows based on a condition","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'An index in a database improves:', '[{"id":"a","text":"Data security","is_correct":false},{"id":"b","text":"Query performance by allowing faster data retrieval at the cost of storage and write speed","is_correct":true},{"id":"c","text":"Data normalization","is_correct":false},{"id":"d","text":"Database backup speed","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is the difference between WHERE and HAVING in SQL?', '[{"id":"a","text":"WHERE filters after GROUP BY; HAVING filters before","is_correct":false},{"id":"b","text":"WHERE filters individual rows before grouping; HAVING filters groups after GROUP BY","is_correct":true},{"id":"c","text":"They are interchangeable","is_correct":false},{"id":"d","text":"WHERE is for JOINs; HAVING is for SELECT statements","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'ACID properties in databases stand for:', '[{"id":"a","text":"Atomicity, Consistency, Isolation, Durability","is_correct":true},{"id":"b","text":"Availability, Concurrency, Integration, Distribution","is_correct":false},{"id":"c","text":"Access, Control, Identity, Data","is_correct":false},{"id":"d","text":"Aggregation, Clustering, Indexing, Deletion","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'An INNER JOIN returns:', '[{"id":"a","text":"All rows from both tables","is_correct":false},{"id":"b","text":"Only the rows that have matching values in both tables","is_correct":true},{"id":"c","text":"All rows from the left table and matching rows from the right","is_correct":false},{"id":"d","text":"All rows from the right table","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is a database transaction?', '[{"id":"a","text":"A payment made to use the database","is_correct":false},{"id":"b","text":"A sequence of operations treated as a single unit that either fully completes or fully fails","is_correct":true},{"id":"c","text":"A data transfer between databases","is_correct":false},{"id":"d","text":"A read-only database query","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is the difference between SQL and NoSQL databases?', '[{"id":"a","text":"SQL is faster; NoSQL is safer","is_correct":false},{"id":"b","text":"SQL stores structured relational data with schemas; NoSQL stores unstructured or semi-structured data with flexible schemas","is_correct":true},{"id":"c","text":"SQL is for small projects; NoSQL for enterprise","is_correct":false},{"id":"d","text":"There is no meaningful difference","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'A composite primary key uses:', '[{"id":"a","text":"Multiple tables to define a key","is_correct":false},{"id":"b","text":"Two or more columns together to uniquely identify a row","is_correct":true},{"id":"c","text":"A primary key that is also a foreign key","is_correct":false},{"id":"d","text":"An auto-incrementing integer across multiple tables","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is a database migration?', '[{"id":"a","text":"Moving a database from one country to another","is_correct":false},{"id":"b","text":"A versioned script that modifies database schema or data in a controlled, repeatable way","is_correct":true},{"id":"c","text":"Importing data from a spreadsheet","is_correct":false},{"id":"d","text":"A backup procedure","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'Row Level Security (RLS) in databases ensures:', '[{"id":"a","text":"All rows are encrypted","is_correct":false},{"id":"b","text":"Different users can only access or modify the specific rows they are authorized to see","is_correct":true},{"id":"c","text":"Rows cannot be deleted","is_correct":false},{"id":"d","text":"Row access is logged for auditing","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is database denormalization and when is it used?', '[{"id":"a","text":"Removing all indexes from the database","is_correct":false},{"id":"b","text":"Intentionally introducing redundancy to improve read performance at the cost of write complexity","is_correct":true},{"id":"c","text":"Converting a relational database to NoSQL","is_correct":false},{"id":"d","text":"Removing duplicate rows from tables","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is a database view?', '[{"id":"a","text":"A graphical interface for exploring a database","is_correct":false},{"id":"b","text":"A saved SQL query that can be queried like a table providing a virtual representation of data","is_correct":true},{"id":"c","text":"A read-only copy of the database","is_correct":false},{"id":"d","text":"A permission level for database users","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What does EXPLAIN do in SQL?', '[{"id":"a","text":"Adds comments to a query","is_correct":false},{"id":"b","text":"Shows the execution plan of a query helping identify performance bottlenecks","is_correct":true},{"id":"c","text":"Describes the structure of a table","is_correct":false},{"id":"d","text":"Returns the query execution time only","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'Stored procedures in a database are:', '[{"id":"a","text":"Automatic backups stored on disk","is_correct":false},{"id":"b","text":"Precompiled SQL code stored in the database that can be executed with parameters","is_correct":true},{"id":"c","text":"Procedures for onboarding new database administrators","is_correct":false},{"id":"d","text":"Functions written in JavaScript","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DB301'), 'multiple_choice', 'What is soft delete in database design?', '[{"id":"a","text":"Deleting records slowly to reduce server load","is_correct":false},{"id":"b","text":"Marking records as deleted with a flag rather than physically removing them, preserving data history","is_correct":true},{"id":"c","text":"Deleting records from non-critical tables only","is_correct":false},{"id":"d","text":"A database cleanup procedure run weekly","is_correct":false}]', 1, true, true, 2);
