INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What is a design system?', '[{"id":"a","text":"A collection of brand logos","is_correct":false},{"id":"b","text":"A set of reusable components, patterns, and guidelines that ensure consistent design across products","is_correct":true},{"id":"c","text":"A project management tool","is_correct":false},{"id":"d","text":"A type of wireframing software","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'Design tokens are:', '[{"id":"a","text":"Security keys for design files","is_correct":false},{"id":"b","text":"Named variables that store design decisions like colors, spacing, and typography for consistent reuse","is_correct":true},{"id":"c","text":"Points earned for completing design courses","is_correct":false},{"id":"d","text":"Placeholder components in a prototype","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What is the primary benefit of using a component library?', '[{"id":"a","text":"It reduces the need for designers","is_correct":false},{"id":"b","text":"It ensures UI consistency and speeds up design and development by providing reusable building blocks","is_correct":true},{"id":"c","text":"It replaces user research","is_correct":false},{"id":"d","text":"It automatically generates code","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'Storybook is a tool used to:', '[{"id":"a","text":"Write user stories for agile teams","is_correct":false},{"id":"b","text":"Document and visually test UI components in isolation","is_correct":true},{"id":"c","text":"Animate design prototypes","is_correct":false},{"id":"d","text":"Track design system adoption metrics","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What does it mean for a design system to be a "living system"?', '[{"id":"a","text":"It is used by living users rather than bots","is_correct":false},{"id":"b","text":"It is continuously updated and maintained to evolve with product needs and usage patterns","is_correct":true},{"id":"c","text":"It has animated components","is_correct":false},{"id":"d","text":"It connects to real-time data","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'Design system governance refers to:', '[{"id":"a","text":"Legal protections for design assets","is_correct":false},{"id":"b","text":"The processes and ownership structures that guide how a design system is maintained and evolved","is_correct":true},{"id":"c","text":"Version control for design files","is_correct":false},{"id":"d","text":"User permission levels in Figma","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'Which of the following is an example of a well-known design system?', '[{"id":"a","text":"Adobe XD","is_correct":false},{"id":"b","text":"Google Material Design","is_correct":true},{"id":"c","text":"Figma Community","is_correct":false},{"id":"d","text":"InVision Studio","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'A pattern library differs from a component library in that:', '[{"id":"a","text":"It only covers typography","is_correct":false},{"id":"b","text":"It documents reusable UI solutions and interactions at a higher level, while component libraries focus on individual elements","is_correct":true},{"id":"c","text":"It is used only by developers","is_correct":false},{"id":"d","text":"It replaces the need for design tokens","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'When should a design system NOT be created?', '[{"id":"a","text":"When a product has multiple teams working on it","is_correct":false},{"id":"b","text":"When a product is a very small one-off project with no plans for growth or reuse","is_correct":true},{"id":"c","text":"When brand consistency is important","is_correct":false},{"id":"d","text":"When a product has multiple platforms","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What is a design system adoption strategy?', '[{"id":"a","text":"A plan to force developers to use only approved components","is_correct":false},{"id":"b","text":"A plan for getting teams to understand, trust, and consistently use the design system","is_correct":true},{"id":"c","text":"A marketing plan for the design system","is_correct":false},{"id":"d","text":"A training schedule for new designers","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'Which Figma feature is most useful for building a design system?', '[{"id":"a","text":"Pen tool","is_correct":false},{"id":"b","text":"Components and variants","is_correct":true},{"id":"c","text":"Slice tool","is_correct":false},{"id":"d","text":"PDF export","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What is the "single source of truth" principle in design systems?', '[{"id":"a","text":"Only one designer can edit the system","is_correct":false},{"id":"b","text":"All teams reference one authoritative, shared design system rather than maintaining separate local versions","is_correct":true},{"id":"c","text":"All design decisions are made by one person","is_correct":false},{"id":"d","text":"Components must only be used in one product","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'How do semantic color tokens differ from base color tokens?', '[{"id":"a","text":"Semantic tokens describe purpose like primary or error, while base tokens describe raw values like blue-500","is_correct":true},{"id":"b","text":"Semantic tokens are used in dark mode only","is_correct":false},{"id":"c","text":"Base tokens are for accessibility, semantic for aesthetics","is_correct":false},{"id":"d","text":"They are the same thing","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What is versioning in the context of a design system?', '[{"id":"a","text":"Tracking how many versions of a file a designer creates","is_correct":false},{"id":"b","text":"Maintaining numbered releases of the system so teams can adopt changes in a controlled way","is_correct":true},{"id":"c","text":"The number of components in the system","is_correct":false},{"id":"d","text":"A way to lock components from editing","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What is a "contribution model" in a design system?', '[{"id":"a","text":"A way to pay contributors for design work","is_correct":false},{"id":"b","text":"A defined process allowing teams outside the core system team to propose and submit new components or patterns","is_correct":true},{"id":"c","text":"A model that tracks design system ROI","is_correct":false},{"id":"d","text":"A template for creating new design files","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What challenge does a design system primarily solve for large product teams?', '[{"id":"a","text":"Reducing the number of designers needed","is_correct":false},{"id":"b","text":"Inconsistency across product surfaces due to teams working in silos without shared standards","is_correct":true},{"id":"c","text":"Eliminating user testing","is_correct":false},{"id":"d","text":"Replacing project management tools","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What is the role of documentation in a design system?', '[{"id":"a","text":"It is optional and rarely useful","is_correct":false},{"id":"b","text":"It helps designers and developers understand when, how, and why to use each component and pattern correctly","is_correct":true},{"id":"c","text":"It replaces design reviews","is_correct":false},{"id":"d","text":"It is only needed for external teams","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'An accessibility audit of a design system should check:', '[{"id":"a","text":"Color contrast ratios, keyboard navigation, focus states, and ARIA label usage","is_correct":true},{"id":"b","text":"Component file sizes only","is_correct":false},{"id":"c","text":"Whether dark mode is supported","is_correct":false},{"id":"d","text":"Brand alignment with marketing guidelines","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'A "federated" design system model means:', '[{"id":"a","text":"The system is built by one central team and pushed to all teams","is_correct":false},{"id":"b","text":"Multiple teams contribute to and maintain different parts of the system under shared governance","is_correct":true},{"id":"c","text":"The system is hosted on a government server","is_correct":false},{"id":"d","text":"Components are split across multiple Figma files","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'DES301'), 'multiple_choice', 'What metric helps measure design system adoption success?', '[{"id":"a","text":"Number of Figma pages","is_correct":false},{"id":"b","text":"Percentage of product UI components sourced from the system versus custom one-off components","is_correct":true},{"id":"c","text":"How many designers are in the team","is_correct":false},{"id":"d","text":"Time taken to export design assets","is_correct":false}]', 1, true, true, 3);
