INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'A stakeholder is best defined as:', '[{"id":"a","text":"Anyone who uses the product","is_correct":false},{"id":"b","text":"Any person or group who has an interest in or is affected by the outcome of a project or product","is_correct":true},{"id":"c","text":"A shareholder in the company","is_correct":false},{"id":"d","text":"The CEO of the organization","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'A stakeholder map is used to:', '[{"id":"a","text":"Show where stakeholders sit in the office","is_correct":false},{"id":"b","text":"Identify and categorize stakeholders by their level of influence and interest in a project","is_correct":true},{"id":"c","text":"Track stakeholder meeting attendance","is_correct":false},{"id":"d","text":"Document stakeholder contact information","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'In a power-interest grid, stakeholders with high power and high interest should be:', '[{"id":"a","text":"Monitored with minimal effort","is_correct":false},{"id":"b","text":"Managed closely with regular and detailed engagement","is_correct":true},{"id":"c","text":"Kept informed through newsletters","is_correct":false},{"id":"d","text":"Excluded from decision-making","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is a RACI matrix used for?', '[{"id":"a","text":"Tracking revenue metrics","is_correct":false},{"id":"b","text":"Clarifying who is Responsible, Accountable, Consulted, and Informed for each task or decision","is_correct":true},{"id":"c","text":"Rating stakeholder satisfaction","is_correct":false},{"id":"d","text":"Mapping product features to user needs","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'When stakeholders have conflicting priorities, the PM should:', '[{"id":"a","text":"Defer to the most senior stakeholder always","is_correct":false},{"id":"b","text":"Facilitate alignment by helping stakeholders understand trade-offs and reach consensus around shared goals","is_correct":true},{"id":"c","text":"Ignore the conflict and proceed with their own plan","is_correct":false},{"id":"d","text":"Escalate immediately to the CEO","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'Executive stakeholders typically care most about:', '[{"id":"a","text":"Specific UI design decisions","is_correct":false},{"id":"b","text":"Business outcomes, strategy alignment, risk, and high-level metrics","is_correct":true},{"id":"c","text":"Technical implementation details","is_correct":false},{"id":"d","text":"Day-to-day sprint activities","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is a communication plan in stakeholder management?', '[{"id":"a","text":"A list of stakeholder email addresses","is_correct":false},{"id":"b","text":"A document defining what information to share with which stakeholders, when, and through which channels","is_correct":true},{"id":"c","text":"A plan for marketing communications","is_correct":false},{"id":"d","text":"A calendar for all team meetings","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'Influence without authority means:', '[{"id":"a","text":"Manipulating stakeholders to get what you want","is_correct":false},{"id":"b","text":"Achieving alignment and buy-in from stakeholders through trust, communication, and persuasion rather than formal power","is_correct":true},{"id":"c","text":"Getting approval from the board","is_correct":false},{"id":"d","text":"Using data to override stakeholder opinions","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is a pre-mortem exercise useful for in stakeholder management?', '[{"id":"a","text":"Celebrating project completion","is_correct":false},{"id":"b","text":"Proactively identifying risks and concerns from stakeholder perspectives before a project begins","is_correct":true},{"id":"c","text":"Reviewing past project failures only","is_correct":false},{"id":"d","text":"Assigning blame for failures","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What does a stakeholder "champion" do?', '[{"id":"a","text":"Evaluates the PM performance annually","is_correct":false},{"id":"b","text":"Advocates for the product or project within the organization, helping secure support and remove obstacles","is_correct":true},{"id":"c","text":"Manages the product budget","is_correct":false},{"id":"d","text":"Writes user stories for the team","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'How should a PM handle a resistant stakeholder?', '[{"id":"a","text":"Exclude them from meetings until they agree","is_correct":false},{"id":"b","text":"Seek to understand their concerns, address root causes, and find mutually acceptable solutions","is_correct":true},{"id":"c","text":"Escalate immediately to their manager","is_correct":false},{"id":"d","text":"Document the resistance and proceed anyway","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is the risk of over-communicating with stakeholders?', '[{"id":"a","text":"Stakeholders become too engaged in product decisions","is_correct":false},{"id":"b","text":"Information overload that causes stakeholders to disengage or miss critical updates","is_correct":true},{"id":"c","text":"The product roadmap changes too frequently","is_correct":false},{"id":"d","text":"It reduces the PM credibility","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is the most important outcome of effective stakeholder alignment?', '[{"id":"a","text":"Stakeholders stop asking for updates","is_correct":false},{"id":"b","text":"A shared understanding of goals, constraints, and trade-offs that enables faster and better decisions","is_correct":true},{"id":"c","text":"The PM gains more authority","is_correct":false},{"id":"d","text":"Fewer meetings are required","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is "scope creep" in relation to stakeholder management?', '[{"id":"a","text":"When the product grows beyond its intended market","is_correct":false},{"id":"b","text":"When stakeholder requests gradually expand project scope beyond original boundaries without proper evaluation","is_correct":true},{"id":"c","text":"When the team moves too slowly","is_correct":false},{"id":"d","text":"When the PM adds features without approval","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'A stakeholder review session serves to:', '[{"id":"a","text":"Replace sprint retrospectives","is_correct":false},{"id":"b","text":"Present progress updates, gather feedback, and realign stakeholder expectations with project reality","is_correct":true},{"id":"c","text":"Train stakeholders on using the product","is_correct":false},{"id":"d","text":"Negotiate salaries for the team","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'Why is it important to manage stakeholder expectations proactively?', '[{"id":"a","text":"To prevent stakeholders from attending sprint reviews","is_correct":false},{"id":"b","text":"To reduce surprises, build trust, and maintain stakeholder confidence even when delivering difficult news","is_correct":true},{"id":"c","text":"To avoid being accountable for product outcomes","is_correct":false},{"id":"d","text":"To ensure stakeholders stay involved in daily decisions","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What does "managing up" mean in product management?', '[{"id":"a","text":"Promoting junior team members","is_correct":false},{"id":"b","text":"Proactively communicating with and influencing senior leaders to gain support, remove blockers, and align on strategy","is_correct":true},{"id":"c","text":"Reporting bugs to engineering leadership","is_correct":false},{"id":"d","text":"Escalating team conflicts to HR","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is the best way to build long-term trust with stakeholders?', '[{"id":"a","text":"Always say yes to their requests","is_correct":false},{"id":"b","text":"Be consistently honest, deliver on commitments, communicate transparently, and demonstrate that their input influences decisions","is_correct":true},{"id":"c","text":"Send frequent status reports regardless of content","is_correct":false},{"id":"d","text":"Avoid conflict at all costs","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'What is a key sign of poor stakeholder management?', '[{"id":"a","text":"Too many stakeholders are aware of the product roadmap","is_correct":false},{"id":"b","text":"Stakeholders are surprised by project decisions, delays, or outcomes that should have been communicated earlier","is_correct":true},{"id":"c","text":"Stakeholders provide too much feedback","is_correct":false},{"id":"d","text":"Stakeholders request fewer meetings","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'PM301'), 'multiple_choice', 'How does a PM balance stakeholder requests against user needs?', '[{"id":"a","text":"Stakeholder requests always take precedence","is_correct":false},{"id":"b","text":"By evaluating requests against user research, business goals, and data, then making evidence-based decisions and communicating trade-offs clearly","is_correct":true},{"id":"c","text":"User needs always take precedence","is_correct":false},{"id":"d","text":"By letting the engineering team decide","is_correct":false}]', 1, true, true, 3);
