INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is an A/B test?', '[{"id":"a","text":"A comparison of two different products","is_correct":false},{"id":"b","text":"An experiment where two versions of something are shown to different groups to determine which performs better","is_correct":true},{"id":"c","text":"A test that checks for software bugs","is_correct":false},{"id":"d","text":"A survey comparing two user groups","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'A null hypothesis in an A/B test states:', '[{"id":"a","text":"The new version will improve the metric","is_correct":false},{"id":"b","text":"There is no difference between the control and variant","is_correct":true},{"id":"c","text":"The test will fail","is_correct":false},{"id":"d","text":"The sample size is sufficient","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'Statistical significance in an A/B test means:', '[{"id":"a","text":"The result is economically meaningful","is_correct":false},{"id":"b","text":"The observed difference is unlikely to have occurred by chance, given the chosen confidence level","is_correct":true},{"id":"c","text":"The sample size is large enough","is_correct":false},{"id":"d","text":"Both variants have identical traffic","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is a control group in an experiment?', '[{"id":"a","text":"The group that receives the new experimental variant","is_correct":false},{"id":"b","text":"The group that experiences the existing version, used as a baseline for comparison","is_correct":true},{"id":"c","text":"The group that provides qualitative feedback","is_correct":false},{"id":"d","text":"The group with the highest conversion rate","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'Why is sample size important in A/B testing?', '[{"id":"a","text":"Larger samples always produce statistically significant results","is_correct":false},{"id":"b","text":"An adequate sample size ensures enough statistical power to reliably detect real differences between variants","is_correct":true},{"id":"c","text":"Sample size determines which variant wins","is_correct":false},{"id":"d","text":"Smaller samples reduce testing costs and are preferred","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is "peeking" in the context of A/B testing?', '[{"id":"a","text":"Reviewing experiment results before users see the variant","is_correct":false},{"id":"b","text":"Stopping a test early when results appear significant, which inflates false positive rates","is_correct":true},{"id":"c","text":"Observing user behavior without their knowledge","is_correct":false},{"id":"d","text":"Reviewing competitor experiments","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is a primary metric in an A/B test?', '[{"id":"a","text":"The most expensive metric to collect","is_correct":false},{"id":"b","text":"The key metric the experiment is designed to move, directly tied to the hypothesis","is_correct":true},{"id":"c","text":"The metric with the highest baseline value","is_correct":false},{"id":"d","text":"The metric measured after the experiment ends","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What does "p-value" represent in statistical testing?', '[{"id":"a","text":"The probability that the variant is better than the control","is_correct":false},{"id":"b","text":"The probability of observing results at least as extreme as the data if the null hypothesis were true","is_correct":true},{"id":"c","text":"The percentage of users in the experiment","is_correct":false},{"id":"d","text":"The statistical power of the test","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is a guardrail metric in experimentation?', '[{"id":"a","text":"The main success metric of the experiment","is_correct":false},{"id":"b","text":"A metric monitored to ensure the experiment does not negatively impact critical business or user outcomes","is_correct":true},{"id":"c","text":"A metric used to determine traffic allocation","is_correct":false},{"id":"d","text":"A metric only relevant for revenue experiments","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is novelty effect in A/B testing?', '[{"id":"a","text":"When users prefer new things simply because they are new, which may inflate initial results of a variant","is_correct":true},{"id":"b","text":"When a test produces novel scientific insights","is_correct":false},{"id":"c","text":"When the experimental variant is completely new to the market","is_correct":false},{"id":"d","text":"When users do not notice any difference between variants","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is the difference between Type I and Type II errors in experimentation?', '[{"id":"a","text":"Type I is detecting no effect; Type II is detecting a false effect","is_correct":false},{"id":"b","text":"Type I is a false positive declaring an effect exists when it does not; Type II is a false negative missing a real effect","is_correct":true},{"id":"c","text":"Type I is a sample size error; Type II is a metric selection error","is_correct":false},{"id":"d","text":"They are the same thing described differently","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is multivariate testing?', '[{"id":"a","text":"Testing multiple products against each other simultaneously","is_correct":false},{"id":"b","text":"An experiment that tests multiple variables or combinations simultaneously to understand their individual and combined effects","is_correct":true},{"id":"c","text":"Testing the same variant across multiple user segments","is_correct":false},{"id":"d","text":"Running multiple A/B tests at the same time","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'Why might an A/B test that is statistically significant not be practically significant?', '[{"id":"a","text":"Statistical significance always implies practical importance","is_correct":false},{"id":"b","text":"The effect size may be too small to justify the cost, effort, or risk of implementing the change","is_correct":true},{"id":"c","text":"Practical significance requires longer experiment runtimes","is_correct":false},{"id":"d","text":"Statistically significant results are never practically relevant","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is network effect contamination in A/B testing?', '[{"id":"a","text":"When experiment results are affected by internet connectivity","is_correct":false},{"id":"b","text":"When control and variant groups interact and influence each other, violating the independence assumption","is_correct":true},{"id":"c","text":"When the experiment spreads to untargeted user groups","is_correct":false},{"id":"d","text":"When results differ across geographic regions","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is Bayesian A/B testing?', '[{"id":"a","text":"A testing method that uses Bayesian statistics to update the probability of a hypothesis being true as data accumulates","is_correct":true},{"id":"b","text":"A test that requires prior customer surveys","is_correct":false},{"id":"c","text":"A method invented by Thomas Bayes for product testing","is_correct":false},{"id":"d","text":"A method that removes the need for sample size planning","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is the purpose of a holdout group in experimentation?', '[{"id":"a","text":"To hold back users from seeing any variant","is_correct":false},{"id":"b","text":"To measure the long-term cumulative impact of multiple experiments by keeping a group unexposed to all changes","is_correct":true},{"id":"c","text":"To reserve traffic for future experiments","is_correct":false},{"id":"d","text":"To test the control version only","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What is an instrumentation check in A/B testing?', '[{"id":"a","text":"Testing the physical experiment hardware","is_correct":false},{"id":"b","text":"Verifying that tracking and data collection are correctly set up before launching an experiment","is_correct":true},{"id":"c","text":"Checking that the experiment UI looks correct","is_correct":false},{"id":"d","text":"A review of past experiment results","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What does "experiment velocity" mean for a product team?', '[{"id":"a","text":"How fast users complete tasks in an experiment","is_correct":false},{"id":"b","text":"The rate at which a team can design, launch, and learn from experiments over time","is_correct":true},{"id":"c","text":"The speed of statistical significance calculation","is_correct":false},{"id":"d","text":"How quickly traffic is allocated to variants","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'When should you NOT run an A/B test?', '[{"id":"a","text":"When you have a strong hypothesis","is_correct":false},{"id":"b","text":"When the change is too small to detect, the audience is too limited, or the ethical implications are problematic","is_correct":true},{"id":"c","text":"When you have enough traffic","is_correct":false},{"id":"d","text":"When you want to improve conversion rates","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'ANA301'), 'multiple_choice', 'What does an experimentation culture in a company look like?', '[{"id":"a","text":"A culture where only senior leaders make data decisions","is_correct":false},{"id":"b","text":"An environment where hypotheses are formed rigorously, experiments are run continuously, and decisions are driven by evidence rather than opinion","is_correct":true},{"id":"c","text":"A culture that avoids risk by testing nothing","is_correct":false},{"id":"d","text":"A team that outsources all experiments to data scientists","is_correct":false}]', 1, true, true, 3);
