INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is the difference between authentication and authorization?', '[{"id":"a","text":"They are the same thing","is_correct":false},{"id":"b","text":"Authentication verifies who you are; authorization determines what you are allowed to do","is_correct":true},{"id":"c","text":"Authentication grants permissions; authorization verifies identity","is_correct":false},{"id":"d","text":"Authorization is only for admin users","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'A JWT (JSON Web Token) consists of:', '[{"id":"a","text":"Username and password encoded in Base64","is_correct":false},{"id":"b","text":"Three parts: header, payload, and signature, each Base64URL encoded and separated by dots","is_correct":true},{"id":"c","text":"A session ID stored on the server","is_correct":false},{"id":"d","text":"An encrypted database record","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is OAuth 2.0 primarily used for?', '[{"id":"a","text":"Encrypting database connections","is_correct":false},{"id":"b","text":"Enabling third-party applications to access user resources without exposing credentials","is_correct":true},{"id":"c","text":"Creating secure passwords","is_correct":false},{"id":"d","text":"Managing server-side sessions","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is an SQL injection attack?', '[{"id":"a","text":"Inserting SQL files into a web server","is_correct":false},{"id":"b","text":"Inserting malicious SQL code into an input field to manipulate or expose database data","is_correct":true},{"id":"c","text":"A method to speed up SQL queries","is_correct":false},{"id":"d","text":"A type of database migration","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is Cross-Site Scripting (XSS)?', '[{"id":"a","text":"When a site copies another site design","is_correct":false},{"id":"b","text":"An attack where malicious scripts are injected into web pages viewed by other users","is_correct":true},{"id":"c","text":"A method to share scripts between websites","is_correct":false},{"id":"d","text":"A form of network interception","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What does HTTPS provide over HTTP?', '[{"id":"a","text":"Faster page load speeds","is_correct":false},{"id":"b","text":"Encrypted communication between client and server using TLS, protecting data in transit","is_correct":true},{"id":"c","text":"Automatic login for users","is_correct":false},{"id":"d","text":"Server-side caching","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is Multi-Factor Authentication (MFA)?', '[{"id":"a","text":"Using multiple passwords for the same account","is_correct":false},{"id":"b","text":"Requiring users to verify their identity using two or more independent methods such as password and OTP","is_correct":true},{"id":"c","text":"Logging in from multiple devices simultaneously","is_correct":false},{"id":"d","text":"An advanced form of biometric authentication only","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is the principle of least privilege?', '[{"id":"a","text":"Giving users minimal training to reduce errors","is_correct":false},{"id":"b","text":"Granting users or systems only the minimum access rights needed to perform their required functions","is_correct":true},{"id":"c","text":"Limiting the number of users in a system","is_correct":false},{"id":"d","text":"Using the simplest security method available","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is password hashing and why is it used?', '[{"id":"a","text":"Encrypting passwords so they can be decrypted later","is_correct":false},{"id":"b","text":"Converting passwords into an irreversible fixed-length string so that plaintext passwords are never stored","is_correct":true},{"id":"c","text":"Compressing passwords for storage efficiency","is_correct":false},{"id":"d","text":"Hiding passwords behind asterisks in the UI","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is a CSRF (Cross-Site Request Forgery) attack?', '[{"id":"a","text":"When a user forges their identity online","is_correct":false},{"id":"b","text":"When a malicious site tricks a user browser into performing unwanted actions on a site where the user is authenticated","is_correct":true},{"id":"c","text":"When scripts are shared across domains","is_correct":false},{"id":"d","text":"When cookies are stolen from a site","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is role-based access control (RBAC)?', '[{"id":"a","text":"A system where access is determined by the user physical location","is_correct":false},{"id":"b","text":"A model where permissions are assigned to roles and users are assigned to roles, controlling what they can access","is_correct":true},{"id":"c","text":"A system that restricts access based on time of day","is_correct":false},{"id":"d","text":"An encryption method for user data","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is token refresh in JWT-based authentication?', '[{"id":"a","text":"Generating a new token every time a user visits the site","is_correct":false},{"id":"b","text":"Using a long-lived refresh token to obtain a new short-lived access token without requiring the user to re-login","is_correct":true},{"id":"c","text":"Updating the JWT signature periodically","is_correct":false},{"id":"d","text":"Refreshing the page to validate authentication","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What does "defense in depth" mean in security?', '[{"id":"a","text":"Using very strong encryption","is_correct":false},{"id":"b","text":"Applying multiple layers of security controls so that if one fails, others still protect the system","is_correct":true},{"id":"c","text":"Defending against the most sophisticated threats only","is_correct":false},{"id":"d","text":"Hiding system internals from users","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is an API key and how should it be stored?', '[{"id":"a","text":"A public identifier stored in the client-side code","is_correct":false},{"id":"b","text":"A secret credential that identifies the calling application, which should be stored in server-side environment variables never in client code","is_correct":true},{"id":"c","text":"A password used by APIs to authenticate users","is_correct":false},{"id":"d","text":"A token stored in localStorage for convenience","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is a security audit?', '[{"id":"a","text":"A review of user login history","is_correct":false},{"id":"b","text":"A systematic evaluation of a system security to identify vulnerabilities, gaps, and improvements","is_correct":true},{"id":"c","text":"An automated scan for malware","is_correct":false},{"id":"d","text":"A log of all database queries","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is the purpose of Content Security Policy (CSP)?', '[{"id":"a","text":"To control which content is paid and which is free","is_correct":false},{"id":"b","text":"To prevent XSS attacks by specifying which sources of content browsers are allowed to load on a page","is_correct":true},{"id":"c","text":"To manage copyright for digital content","is_correct":false},{"id":"d","text":"To encrypt page content for GDPR compliance","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is rate limiting in the context of API security?', '[{"id":"a","text":"Limiting the size of API responses","is_correct":false},{"id":"b","text":"Restricting how many requests a client can make in a given time period to prevent abuse and denial-of-service attacks","is_correct":true},{"id":"c","text":"Setting a maximum data transfer rate","is_correct":false},{"id":"d","text":"Prioritizing API calls from premium users","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What is a penetration test?', '[{"id":"a","text":"A stress test of server performance","is_correct":false},{"id":"b","text":"An authorized simulated attack on a system to identify exploitable security vulnerabilities before malicious actors do","is_correct":true},{"id":"c","text":"Testing whether users can bypass paywalls","is_correct":false},{"id":"d","text":"A test of network penetration speed","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'What does GDPR require regarding user data?', '[{"id":"a","text":"All user data must be stored on EU servers","is_correct":false},{"id":"b","text":"Organizations must obtain lawful consent for data collection, protect data, and provide users rights over their personal data","is_correct":true},{"id":"c","text":"User passwords must be disclosed to regulators","is_correct":false},{"id":"d","text":"All data must be encrypted with government-approved algorithms","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'SYS302'), 'multiple_choice', 'Why is security considered a product feature rather than just a technical concern?', '[{"id":"a","text":"Because security is only relevant during development","is_correct":false},{"id":"b","text":"Because users trust and choose products based on how safely their data is handled, making security a competitive and ethical differentiator","is_correct":true},{"id":"c","text":"Because security is only relevant for financial products","is_correct":false},{"id":"d","text","is_correct":false},{"id":"d","text":"Because marketing teams control security messaging","is_correct":false}]', 1, true, true, 3);
