INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What does DevOps primarily aim to achieve?', '[{"id":"a","text":"Replacing developers with operations staff","is_correct":false},{"id":"b","text":"Breaking down silos between development and operations to enable faster and more reliable software delivery","is_correct":true},{"id":"c","text":"Automating all manual design work","is_correct":false},{"id":"d","text":"Moving all software to the cloud","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is Continuous Integration (CI)?', '[{"id":"a","text":"Continuously adding new features to a product","is_correct":false},{"id":"b","text":"A practice where developers frequently merge code into a shared repository, with automated builds and tests run on each merge","is_correct":true},{"id":"c","text":"A tool for managing server infrastructure","is_correct":false},{"id":"d","text":"Automatically deploying to production on every commit","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is Continuous Deployment (CD)?', '[{"id":"a","text":"A practice where code is manually reviewed before shipping","is_correct":false},{"id":"b","text":"Automatically deploying every code change that passes all tests to production without manual intervention","is_correct":true},{"id":"c","text":"Deploying software on a fixed schedule","is_correct":false},{"id":"d","text":"A testing methodology for staging environments","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is a staging environment?', '[{"id":"a","text":"A backup copy of the production database","is_correct":false},{"id":"b","text":"A pre-production environment that mirrors production, used to test changes before releasing them to real users","is_correct":true},{"id":"c","text":"A server where developers write code","is_correct":false},{"id":"d","text":"An environment for storing old versions of the software","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is a feature flag?', '[{"id":"a","text":"A visual indicator in the UI for new features","is_correct":false},{"id":"b","text":"A configuration that enables or disables a feature for specific users without deploying new code","is_correct":true},{"id":"c","text":"A flag in git marking a feature branch","is_correct":false},{"id":"d","text":"A label applied to completed features in Jira","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is a canary deployment?', '[{"id":"a","text":"A deployment made for testing purposes only","is_correct":false},{"id":"b","text":"Releasing a new version to a small subset of users before rolling it out to everyone, to reduce risk","is_correct":true},{"id":"c","text":"Deploying only during off-peak hours","is_correct":false},{"id":"d","text":"A rollback procedure for failed deployments","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What does "infrastructure as code" (IaC) mean?', '[{"id":"a","text":"Writing code that runs on server hardware","is_correct":false},{"id":"b","text":"Managing and provisioning infrastructure through machine-readable configuration files rather than manual processes","is_correct":true},{"id":"c","text":"Hosting code repositories on physical servers","is_correct":false},{"id":"d","text":"Writing server-side code for APIs","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is a rollback in deployment?', '[{"id":"a","text":"Rolling out a new deployment to all users","is_correct":false},{"id":"b","text":"Reverting to a previous stable version of software when a new deployment causes problems","is_correct":true},{"id":"c","text":"A gradual increase in server capacity","is_correct":false},{"id":"d","text":"Reviewing deployment logs after release","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What does application monitoring provide?', '[{"id":"a","text":"Code review for developers","is_correct":false},{"id":"b","text":"Real-time visibility into application performance, error rates, and system health so teams can detect and respond to issues quickly","is_correct":true},{"id":"c","text":"Automated testing of new features","is_correct":false},{"id":"d","text":"User behavior tracking for product analytics","is_correct":false}]', 1, true, false, 1);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is the purpose of a Git branching strategy like GitFlow?', '[{"id":"a","text":"To prevent developers from committing directly to main","is_correct":false},{"id":"b","text":"To provide a structured workflow for managing features, releases, and hotfixes through dedicated branches","is_correct":true},{"id":"c","text":"To automate merging of all branches weekly","is_correct":false},{"id":"d","text":"To eliminate the need for code reviews","is_correct":false}]', 1, true, false, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is a deployment pipeline?', '[{"id":"a","text":"A physical cable connecting servers","is_correct":false},{"id":"b","text":"An automated sequence of steps that builds, tests, and deploys code to one or more environments","is_correct":true},{"id":"c","text":"A schedule for weekly software releases","is_correct":false},{"id":"d","text":"A project management workflow for releases","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is the difference between horizontal and vertical scaling?', '[{"id":"a","text":"Horizontal scaling increases server speed; vertical scaling adds more servers","is_correct":false},{"id":"b","text":"Horizontal scaling adds more servers to distribute load; vertical scaling increases resources on existing servers","is_correct":true},{"id":"c","text":"They are equivalent approaches","is_correct":false},{"id":"d","text":"Horizontal scaling applies only to databases","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is an SLA (Service Level Agreement) in the context of DevOps?', '[{"id":"a","text":"A legal contract between two software companies","is_correct":false},{"id":"b","text":"A formal commitment defining expected levels of service reliability, availability, and performance between a provider and customer","is_correct":true},{"id":"c","text":"A list of tasks assigned to the operations team","is_correct":false},{"id":"d","text":"A tool for tracking deployment frequency","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What does observability mean in software systems?', '[{"id":"a","text":"The ability of developers to view user screens remotely","is_correct":false},{"id":"b","text":"The degree to which internal states of a system can be inferred from external outputs like logs, metrics, and traces","is_correct":true},{"id":"c","text":"The visibility of code repositories to all team members","is_correct":false},{"id":"d","text":"Monitoring which users are currently logged in","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is a post-mortem in DevOps culture?', '[{"id":"a","text":"An end-of-project celebration","is_correct":false},{"id":"b","text":"A blameless review of an incident to understand what happened, why, and how to prevent recurrence","is_correct":true},{"id":"c","text":"A performance review for engineers","is_correct":false},{"id":"d","text":"A decommission plan for old software","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is container orchestration?', '[{"id":"a","text":"Managing the visual layout of containerized apps","is_correct":false},{"id":"b","text":"Automated management of the deployment, scaling, networking, and lifecycle of containers across a cluster","is_correct":true},{"id":"c","text":"Manually starting and stopping Docker containers","is_correct":false},{"id":"d","text":"Organizing application files into containers","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is a zero-downtime deployment?', '[{"id":"a","text":"A deployment that takes no time to complete","is_correct":false},{"id":"b","text":"A deployment strategy where new code is released without making the service unavailable to users","is_correct":true},{"id":"c","text":"A deployment with no code changes","is_correct":false},{"id":"d","text":"A deployment that skips all automated tests","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What does DORA (DevOps Research and Assessment) measure?', '[{"id":"a","text":"Developer satisfaction scores","is_correct":false},{"id":"b","text":"Four key metrics: deployment frequency, lead time for changes, change failure rate, and time to restore service","is_correct":true},{"id":"c","text":"The number of servers in a deployment","is_correct":false},{"id":"d","text":"Code review completion rates","is_correct":false}]', 1, true, true, 3);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'What is technical debt in the context of DevOps?', '[{"id":"a","text":"Money owed to cloud service providers","is_correct":false},{"id":"b","text":"The accumulated cost of shortcuts and suboptimal decisions in code or infrastructure that will need to be addressed later","is_correct":true},{"id":"c","text":"Outstanding software licenses","is_correct":false},{"id":"d","text":"Time spent on non-product tasks","is_correct":false}]', 1, true, true, 2);
INSERT INTO questions (course_id, type, question_text, options, points, shuffle_options, is_exam_question, difficulty) VALUES ((SELECT id FROM courses WHERE code = 'OPS302'), 'multiple_choice', 'Why is blameless culture important in DevOps?', '[{"id":"a","text":"It ensures no one is held accountable for failures","is_correct":false},{"id":"b","text":"It encourages teams to report incidents honestly, learn from failures, and improve systems without fear of punishment","is_correct":true},{"id":"c","text":"It removes the need for code reviews","is_correct":false},{"id":"d","text":"It reduces the number of deployments to avoid failures","is_correct":false}]', 1, true, true, 2);
